//! # Rune - TypeScript to Rust Compiler Driver
//!
//! A compiler driver that makes `*.r.ts` and `*.r.tsx` valid source files
//! for Rust projects with zero runtime overhead.

#![warn(clippy::all, clippy::pedantic, clippy::nursery)]
#![deny(
    unsafe_code,
    bare_trait_objects,
    ellipsis_inclusive_range_patterns,
    exported_private_dependencies,
    keyword_idents,
    macro_use_extern_crate,
    meta_variable_misuse,
    missing_abi,
    non_ascii_idents,
    noop_method_prelude,
    pointer_structural_match,
    single_char_lifetime_names,
    trivial_casts,
    trivial_numeric_casts,
    unreachable_pub,
    unused_extern_crates,
    unused_import_braces,
    unused_lifetimes,
    unused_qualifications,
)]
#![allow(clippy::module_name_repetitions)]

pub mod analyzer;
pub mod codegen;
pub mod driver;
pub mod parser;
pub mod reload;

use thiserror::Error;

/// Result type for Rune operations.
pub type Result<T> = std::result::Result<T, RuneError>;

/// Errors that can occur during Rune compilation.
#[derive(Error, Debug)]
pub enum RuneError {
    #[error("Parse error: {0}")]
    Parse(#[from] ParseError),

    #[error("Analysis error at {location}: {message}")]
    Analysis { location: String, message: String },

    #[error("Codegen error: {0}")]
    Codegen(String),

    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    #[error("Cargo error: {0}")]
    Cargo(String),

    #[error("Hot reload error: {0}")]
    Reload(String),
}

/// Parse errors from SWC.
#[derive(Error, Debug)]
pub enum ParseError {
    #[error("SWC error: {0}")]
    Swc(String),

    #[error("File not found: {0}")]
    NotFound(String),

    #[error("Invalid file extension: {0}")]
    InvalidExtension(String),
}

/// Location in source code.
#[derive(Debug, Clone, Default)]
pub struct SourceLocation {
    pub file: String,
    pub line: u32,
    pub column: u32,
}

impl std::fmt::Display for SourceLocation {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}:{}:{}", self.file, self.line, self.column)
    }
}

//! Rune compiler CLI entry point.

fn main() {
    rune_cli::main();
}

//! # Parser Module - SWC Integration
//!
//! Parses `*.r.ts` and `*.r.tsx` files into valid TypeScript AST.
//! Enforces file extension validation and UTF-8 encoding.

mod source_file;
mod diagnostics;

pub use source_file::{SourceFile, SourceKind};
pub use diagnostics::ParseDiagnostics;

/// Parse a Rune source file using SWC.
/// Returns the parsed AST module or an error.
pub fn parse_file(path: &std::path::Path) -> crate::Result<SourceFile> {
    let extension = path
        .extension()
        .and_then(|e| e.to_str())
        .ok_or_else(|| crate::ParseError::InvalidExtension(String::new()))?;

    let kind = match extension {
        "r.ts" => SourceKind::TypeScript,
        "r.tsx" => SourceKind::Tsx,
        "rs" => return Ok(SourceFile::from_rust_file(path)?),
        _ => {
            return Err(crate::ParseError::InvalidExtension(extension.to_string()).into());
        }
    };

    SourceFile::parse(path, kind)
}

/// Scan a directory for all Rune source files.
pub fn scan_directory(dir: &std::path::Path) -> crate::Result<Vec<std::path::PathBuf>> {
    let mut sources = Vec::new();
    scan_directory_impl(dir, &mut sources)?;
    Ok(sources)
}

fn scan_directory_impl(dir: &std::path::Path, sources: &mut Vec<std::path::PathBuf>) -> crate::Result<()> {
    if !dir.is_dir() {
        return Ok(());
    }

    for entry in walkdir::WalkDir::new(dir)
        .follow_links(true)
        .into_iter()
        .filter_map(|e| e.ok())
    {
        let path = entry.path();
        if !path.is_file() {
            continue;
        }

        if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
            if ext == "r.ts" || ext == "r.tsx" {
                sources.push(path.to_path_buf());
            }
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_extension_validation() {
        assert!(matches!(
            parse_file(std::path::Path::new("test.r.ts")),
            Ok(SourceFile {
                kind: SourceKind::TypeScript,
                ..
            })
        ));

        assert!(matches!(
            parse_file(std::path::Path::new("test.r.tsx")),
            Ok(SourceFile {
                kind: SourceKind::Tsx,
                ..
            })
        ));

        assert!(parse_file(std::path::Path::new("test.ts")).is_err());
        assert!(parse_file(std::path::Path::new("test.js")).is_err());
    }
}

//! # Source File Handling
//!
//! Manages source file parsing with SWC and provides the AST.

use std::fs;
use std::path::Path;
use swc_common::{
    errors::{ColorConfig, Handler},
    sync::Lrc,
    FileName, SourceMap,
};
use swc_ecma_ast::*;
use swc_ecma_parser::{lexer::Lexer, Parser, StringInput, Syntax, TsConfig};

use crate::{ParseError, Result};

/// Kind of source file.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SourceKind {
    /// Standard TypeScript file (.r.ts)
    TypeScript,
    /// TSX file (.r.tsx)
    Tsx,
}

/// A parsed Rune source file.
#[derive(Debug, Clone)]
pub struct SourceFile {
    /// File path
    pub path: PathBuf,
    /// Kind of source file
    pub kind: SourceKind,
    /// Raw source text
    pub source: String,
    /// SWC AST module
    pub module: Module,
    /// Source map reference
    pub source_map: Lrc<SourceMap>,
}

impl SourceFile {
    /// Parse a source file from a path.
    pub fn parse(path: &Path, kind: SourceKind) -> Result<Self> {
        if !path.exists() {
            return Err(ParseError::NotFound(path.display().to_string()).into());
        }

        let source = fs::read_to_string(path)?;
        let path_str = path.display().to_string();

        let cm: Lrc<SourceMap> = Default::default();
        let fm = cm.new_source_file(FileName::Real(path_str.clone().into()).into(), source.clone());

        let syntax = match kind {
            SourceKind::TypeScript => Syntax::Typescript(TsConfig {
                tsx: false,
                decorators: false,
                dts: false,
                no_early_errors: false,
                disallow_ambiguous_jsx_like: true,
            }),
            SourceKind::Tsx => Syntax::Typescript(TsConfig {
                tsx: true,
                decorators: false,
                dts: false,
                no_early_errors: false,
                disallow_ambiguous_jsx_like: true,
            }),
        };

        let lexer = Lexer::new(
            syntax,
            Default::default(),
            StringInput::from(&*fm),
            None,
        );

        let mut parser = Parser::new_from(lexer);
        let module = parser
            .parse_module()
            .map_err(|e| ParseError::Swc(e.to_string()))?;

        Ok(Self {
            path: path.to_path_buf(),
            kind,
            source,
            module,
            source_map: cm,
        })
    }

    /// Parse a Rust file (for native interop).
    pub fn from_rust_file(path: &Path) -> Result<Self> {
        if !path.exists() {
            return Err(ParseError::NotFound(path.display().to_string()).into());
        }

        let source = fs::read_to_string(path)?;
        let path_str = path.display().to_string();

        let cm: Lrc<SourceMap> = Default::default();
        let fm = cm.new_source_file(FileName::Real(path_str.clone().into()).into(), source.clone());

        let lexer = Lexer::new(
            Syntax::Typescript(TsConfig {
                tsx: false,
                decorators: false,
                dts: false,
                no_early_errors: false,
                disallow_ambiguous_jsx_like: true,
            }),
            Default::default(),
            StringInput::from(&*fm),
            None,
        );

        let mut parser = Parser::new_from(lexer);
        let module = parser
            .parse_module()
            .map_err(|e| ParseError::Swc(e.to_string()))?;

        Ok(Self {
            path: path.to_path_buf(),
            kind: SourceKind::TypeScript,
            source,
            module,
            source_map: cm,
        })
    }

    /// Get line and column from byte offset.
    pub fn location_from_offset(&self, offset: u32) -> (u32, u32) {
        let fm = self.source_map.get_source_file(&self.module.span).unwrap();
        let loc = fm.lookup_char_pos(swc_common::BytePos(offset));
        (loc.line, loc.col.0 + 1)
    }
}

