//! # Parse Diagnostics
//!
//! Collects and formats parse errors from SWC.

use swc_common::{errors::Handler, ColorConfig, SourceMap};
use swc_ecma_parser::error::Error;

use crate::ParseError;

/// Accumulated parse diagnostics.
#[derive(Debug, Default)]
pub struct ParseDiagnostics {
    errors: Vec<ParseError>,
}

impl ParseDiagnostics {
    /// Create a new diagnostics collector.
    pub fn new() -> Self {
        Self { errors: Vec::new() }
    }

    /// Add an error.
    pub fn add_error(&mut self, err: ParseError) {
        self.errors.push(err);
    }

    /// Check if there are any errors.
    pub fn has_errors(&self) -> bool {
        !self.errors.is_empty()
    }

    /// Get all errors.
    pub fn errors(&self) -> &[ParseError] {
        &self.errors
    }

    /// Take all errors, leaving an empty collector.
    pub fn take_errors(&mut self) -> Vec<ParseError> {
        std::mem::take(&mut self.errors)
    }

    /// Format errors as a string.
    pub fn format(&self) -> String {
        self.errors
            .iter()
            .map(|e| format!("  - {e}"))
            .collect::<Vec<_>>()
            .join("\n")
    }
}

impl std::fmt::Display for ParseDiagnostics {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Parse errors:\n{}", self.format())
    }
}

//! # Analyzer Module
//!
//! Validates the zero-overhead TypeScript subset and performs
//! ownership inference (borrow checking).

mod validator;
mod type_inference;
mod ownership;
mod context;

pub use validator::{SubsetValidator, ValidationError};
pub use type_inference::TypeInferrer;
pub use ownership::{OwnershipAnalyzer, BorrowMode};
pub use context::AnalysisContext;

/// Full analysis result for a source file.
#[derive(Debug, Clone)]
pub struct AnalysisResult {
    /// Validated types
    pub types: TypeMap,
    /// Ownership analysis per binding
    pub ownership: OwnershipAnalysis,
    /// Warnings generated during analysis
    pub warnings: Vec<AnalysisWarning>,
}

/// Type mapping for a file.
#[derive(Debug, Clone, Default)]
pub struct TypeMap {
    entries: std::collections::HashMap<String, TypeInfo>,
}

impl TypeMap {
    /// Insert a type for a binding.
    pub fn insert(&mut self, name: String, info: TypeInfo) {
        self.entries.insert(name, info);
    }

    /// Get type info for a binding.
    pub fn get(&self, name: &str) -> Option<&TypeInfo> {
        self.entries.get(name)
    }

    /// Iterate over all entries.
    pub fn iter(&self) -> impl Iterator<Item = (&str, &TypeInfo)> {
        self.entries.iter().map(|(k, v)| (k.as_str(), v))
    }
}

/// Type information inferred from TypeScript.
#[derive(Debug, Clone)]
pub enum TypeInfo {
    /// Integer literal
    Integer(i64),
    /// Floating point
    Float,
    /// String type
    String,
    /// String literal
    StringLiteral(String),
    /// Boolean
    Boolean,
    /// Array type
    Array(Box<TypeInfo>),
    /// Struct type
    Struct(StructInfo),
    /// Enum type (tagged union)
    Enum(EnumInfo),
    /// Option type
    Option(Box<TypeInfo>),
    /// Result type
    Result(Box<TypeInfo>, Box<TypeInfo>),
    /// Function type
    Function(FunctionInfo),
    /// Unknown type (error)
    Unknown,
}

/// Struct type information.
#[derive(Debug, Clone)]
pub struct StructInfo {
    pub name: String,
    pub fields: Vec<(String, TypeInfo)>,
}

/// Enum type information (tagged union).
#[derive(Debug, Clone)]
pub struct EnumInfo {
    pub name: String,
    pub variants: Vec<EnumVariant>,
}

/// Enum variant.
#[derive(Debug, Clone)]
pub struct EnumVariant {
    pub tag: String,
    pub fields: Vec<(String, TypeInfo)>,
}

/// Function type information.
#[derive(Debug, Clone)]
pub struct FunctionInfo {
    pub params: Vec<(String, TypeInfo)>,
    pub return_type: TypeInfo,
    pub is_async: bool,
}

/// Ownership analysis per binding.
#[derive(Debug, Clone, Default)]
pub struct OwnershipAnalysis {
    bindings: std::collections::HashMap<String, BorrowMode>,
}

impl OwnershipAnalysis {
    /// Record borrow mode for a binding.
    pub fn set(&mut self, name: String, mode: BorrowMode) {
        self.bindings.insert(name, mode);
    }

    /// Get borrow mode for a binding.
    pub fn get(&self, name: &str) -> Option<BorrowMode> {
        self.bindings.get(name).copied()
    }
}

/// Warnings generated during analysis.
#[derive(Debug, Clone)]
pub struct AnalysisWarning {
    pub location: String,
    pub message: String,
    pub code: &'static str,
}

/// Analyze a source file.
pub fn analyze(source: &crate::parser::SourceFile) -> crate::Result<AnalysisResult> {
    let mut ctx = AnalysisContext::new(source);
    let validator = SubsetValidator::new();
    let type_inferrer = TypeInferrer::new();
    let ownership_analyzer = OwnershipAnalyzer::new();

    validator.validate_module(&source.module, &mut ctx)?;
    let types = type_inferrer.infer_types(&source.module, &ctx)?;
    let ownership = ownership_analyzer.analyze(&source.module, &ctx)?;
    let warnings = ctx.take_warnings();

    Ok(AnalysisResult {
        types,
        ownership,
        warnings,
    })
}

//! # Subset Validator
//!
//! Validates that TypeScript code uses only the zero-overhead subset.
//! Rejects forbidden features like `any`, `class`, `try/catch`, etc.

use swc_ecma_ast::*;
use super::context::AnalysisContext;

/// Validation error with source location.
#[derive(Debug, Clone)]
pub struct ValidationError {
    pub location: String,
    pub message: String,
    pub code: &'static str,
}

impl std::fmt::Display for ValidationError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}: {}", self.location, self.message)
    }
}

/// Validates the zero-overhead TypeScript subset.
#[derive(Debug, Default)]
pub struct SubsetValidator {
    /// Current depth for complexity tracking
    complexity: usize,
}

impl SubsetValidator {
    /// Create a new validator.
    pub fn new() -> Self {
        Self { complexity: 0 }
    }

    /// Validate an entire module.
    pub fn validate_module(&mut self, module: &Module, ctx: &mut AnalysisContext) -> crate::Result<()> {
        for item in &module.body {
            self.validate_module_item(item, ctx)?;
        }
        Ok(())
    }

    /// Validate a module item.
    fn validate_module_item(&mut self, item: &ModuleItem, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.validate_decl(decl, ctx),
            ModuleItem::Stmt(Stmt::Expr(expr)) => self.validate_expr(&expr.expr, ctx),
            ModuleItem::ModuleDecl(decl) => self.validate_module_decl(decl, ctx),
            _ => Ok(()),
        }
    }

    /// Validate a declaration.
    fn validate_decl(&mut self, decl: &Decl, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match decl {
            Decl::Fn(f) => self.validate_function(&f.function, ctx),
            Decl::Var(v) => {
                self.validate_var_decl(v, ctx)?;
                Ok(())
            }
            Decl::Class(_) => Err(self.error(ctx, "Classes are forbidden. Use plain objects.")),
            Decl::TsInterface(_) => Ok(()),
            Decl::TsTypeAlias(t) => self.validate_ts_type(&t.type_ann, ctx),
            Decl::TsEnum(e) => self.validate_ts_enum(e, ctx),
            Decl::TsModule(_) => Ok(()),
        }
    }

    /// Validate a variable declaration.
    fn validate_var_decl(&mut self, v: &VarDecl, ctx: &mut AnalysisContext) -> crate::Result<()> {
        if v.kind != VarDeclKind::Var {
            // const and let are allowed
        }
        for decl in &v.decls {
            if let Some(init) = &decl.init {
                self.validate_expr(init, ctx)?;
            }
        }
        Ok(())
    }

    /// Validate a function.
    fn validate_function(&mut self, f: &Function, ctx: &mut AnalysisContext) -> crate::Result<()> {
        self.complexity += 1;
        if self.complexity > 10 {
            ctx.add_warning(
                ctx.current_location(),
                "High cyclomatic complexity detected".into(),
                "complexity",
            );
        }

        let result = f.body.as_ref().map_or(Ok(()), |b| self.validate_stmt(b, ctx));

        self.complexity -= 1;
        result
    }

    /// Validate a statement.
    fn validate_stmt(&mut self, stmt: &Stmt, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match stmt {
            Stmt::Expr(e) => self.validate_expr(&e.expr, ctx),
            Stmt::If(i) => {
                self.validate_expr(&i.test, ctx)?;
                self.validate_stmt(&i.cons, ctx)?;
                if let Some(alt) = &i.alt {
                    self.validate_stmt(alt, ctx)?;
                }
                Ok(())
            }
            Stmt::While(w) => {
                self.validate_expr(&w.test, ctx)?;
                self.validate_stmt(&w.body, ctx)
            }
            Stmt::For(f) => {
                if let Some(init) = &f.init {
                    match init {
                        VarDeclOrExpr::VarDecl(v) => self.validate_var_decl(v, ctx)?,
                        VarDeclOrExpr::Expr(e) => self.validate_expr(e, ctx)?,
                    }
                }
                if let Some(test) = &f.test {
                    self.validate_expr(test, ctx)?;
                }
                if let Some(update) = &f.update {
                    self.validate_expr(update, ctx)?;
                }
                self.validate_stmt(&f.body, ctx)
            }
            Stmt::ForIn(f) => {
                // Only allowed for arrays with Object.keys() pattern
                self.validate_expr(&f.right, ctx)?;
                self.validate_stmt(&f.body, ctx)
            }
            Stmt::ForOf(f) => {
                self.validate_expr(&f.right, ctx)?;
                self.validate_stmt(&f.body, ctx)
            }
            Stmt::DoWhile(d) => {
                self.validate_stmt(&d.body, ctx)?;
                self.validate_expr(&d.test, ctx)
            }
            Stmt::Switch(s) => {
                self.validate_expr(&s.discriminant, ctx)?;
                for case in &s.cases {
                    if let Some(test) = &case.test {
                        self.validate_expr(test, ctx)?;
                    }
                    for item in &case.cons {
                        self.validate_stmt(item, ctx)?;
                    }
                }
                Ok(())
            }
            Stmt::Block(b) => {
                for stmt in &b.stmts {
                    self.validate_stmt(stmt, ctx)?;
                }
                Ok(())
            }
            Stmt::Try(t) => Err(self.error(ctx, "try/catch is forbidden. Use Result<T,E> pattern.")),
            Stmt::Throw(_) => Err(self.error(ctx, "throw is forbidden. Use Result<T,E> pattern.")),
            Stmt::Return(r) => {
                r.value.as_ref().map_or(Ok(()), |e| self.validate_expr(e, ctx))
            }
            Stmt::Break(_) | Stmt::Continue(_) => Ok(()),
            Stmt::With(_) => Err(self.error(ctx, "with is forbidden.")),
            Stmt::Labeled(l) => self.validate_stmt(&l.body, ctx),
            Stmt::Empty(_) => Ok(()),
            Stmt::Debugger(_) => Ok(()),
            Stmt::Decl(d) => self.validate_decl(d, ctx),
        }
    }

    /// Validate an expression.
    fn validate_expr(&mut self, expr: &Expr, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match expr {
            Expr::Ident(_) => Ok(()),
            Expr::Lit(l) => self.validate_lit(l, ctx),
            Expr::Bin(b) => {
                self.validate_expr(&b.left, ctx)?;
                self.validate_expr(&b.right, ctx)?;
                // Check for loose equality
                if matches!(b.op, BinaryOp::EqEq | BinaryOp::NotEq) {
                    return Err(self.error(ctx, "Use === instead of ==".into()));
                }
                // Warn about potential integer division
                if matches!(b.op, BinaryOp::Div) {
                    self.check_integer_division(b, ctx);
                }
                Ok(())
            }
            Expr::Unary(u) => self.validate_expr(&u.arg, ctx),
            Expr::Update(u) => self.validate_expr(&u.arg, ctx),
            Expr::Assign(a) => {
                self.validate_expr(&a.left, ctx)?;
                self.validate_expr(&a.value, ctx)
            }
            Expr::Member(m) => {
                self.validate_expr(&m.obj, ctx)?;
                if m.computed {
                    // Dynamic property access - only allowed for arrays
                    let obj_type = ctx.infer_type(&m.obj);
                    if !matches!(obj_type, Some(super::TypeInfo::Array(_))) {
                        return Err(self.error(ctx, "Dynamic property access is forbidden. Use Map<K,V>.".into()));
                    }
                }
                if let Some(prop) = &m.prop {
                    self.validate_expr(prop, ctx)?;
                }
                Ok(())
            }
            Expr::Call(c) => {
                self.validate_expr(&c.callee, ctx)?;
                for arg in &c.args {
                    self.validate_expr(&arg.expr, ctx)?;
                }
                Ok(())
            }
            Expr::New(n) => Err(self.error(ctx, "new is forbidden. Use factory functions.".into())),
            Expr::Arrow(f) => {
                for param in &f.params {
                    if let Pat::Assign(a) = &param.pat {
                        self.validate_expr(&a.right, ctx)?;
                    }
                }
                self.validate_expr(&f.body, ctx)
            }
            Expr::Fn(f) => self.validate_function(&f.function, ctx),
            Expr::Class(c) => Err(self.error(ctx, "Classes are forbidden. Use plain objects.".into())),
            Expr::Seq(s) => {
                for expr in &s.exprs {
                    self.validate_expr(expr, ctx)?;
                }
                Ok(())
            }
            Expr::Cond(c) => {
                self.validate_expr(&c.test, ctx)?;
                self.validate_expr(&c.cons, ctx)?;
                self.validate_expr(&c.alt, ctx)
            }
            Expr::Await(a) => self.validate_expr(&a.arg, ctx),
            Expr::Paren(p) => self.validate_expr(&p.expr, ctx),
            Expr::Tpl(t) => {
                for expr in &t.exprs {
                    self.validate_expr(expr, ctx)?;
                }
                Ok(())
            }
            Expr::TaggedTpl(t) => {
                self.validate_expr(&t.tag, ctx)?;
                for expr in &t.tpl.exprs {
                    self.validate_expr(expr, ctx)?;
                }
                Ok(())
            }
            Expr::Array(a) => {
                for elem in &a.elems {
                    if let Some(e) = elem {
                        self.validate_expr(&e.expr, ctx)?;
                    }
                }
                Ok(())
            }
            Expr::Object(o) => {
                for prop in &o.props {
                    match prop {
                        PropOrSpread::Prop(p) => self.validate_prop(p, ctx),
                        PropOrSpread::Spread(s) => self.validate_expr(&s.expr, ctx),
                    }
                }
                Ok(())
            }
            Expr::This(_) => Err(self.error(ctx, "this is forbidden. Use explicit parameters.".into())),
            Expr::Yield(_) => Err(self.error(ctx, "yield is forbidden.".into())),
            Expr::MetaProp(_) => Err(self.error(ctx, "Meta properties are forbidden.".into())),
            Expr::Super(_) => Err(self.error(ctx, "super is forbidden.".into())),
            Expr::TsTypeAssertion(t) => self.validate_expr(&t.expr, ctx),
            Expr::TsAs(t) => self.validate_expr(&t.expr, ctx),
            Expr::TsNonNull(t) => self.validate_expr(&t.expr, ctx),
            Expr::TsSatisfies(t) => self.validate_expr(&t.expr, ctx),
            Expr::Jsx(_) => Ok(()), // Handled by JSX-specific validation
            Expr::Invalid(_) => Err(self.error(ctx, "Invalid expression.".into())),
        }
    }

    /// Validate a literal.
    fn validate_lit(&self, lit: &Lit, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match lit {
            Lit::Null(_) => Ok(()),
            Lit::Bool(_) | Lit::Num(_) | Lit::Str(_) | Lit::BigInt(_) => Ok(()),
            Lit::Regex(_) => Err(self.error(ctx, "Regex literals are forbidden.".into())),
            Lit::JSXText(_) => Ok(()),
        }
    }

    /// Validate an object property.
    fn validate_prop(&self, prop: &Prop, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match prop {
            Prop::Shorthand(i) => Ok(()),
            Prop::KeyValue(k) => {
                self.validate_expr(&k.value, ctx)
            }
            Prop::Assign(a) => self.validate_expr(&a.value, ctx),
            Prop::Getter(g) => self.validate_expr(&g.body.as_ref().unwrap_or(&BlockStmtOrExpr::Invalid(Invalid { span: Default::default() })), ctx),
            Prop::Setter(s) => {
                if let Some(param) = &s.param {
                    self.validate_pat(param, ctx)?;
                }
                Ok(())
            }
            Prop::Method(m) => self.validate_function(&m.function, ctx),
        }
    }

    /// Validate a pattern.
    fn validate_pat(&self, pat: &Pat, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match pat {
            Pat::Ident(i) => Ok(()),
            Pat::Array(a) => {
                for elem in &a.elems {
                    if let Some(p) = elem {
                        self.validate_pat(p, ctx)?;
                    }
                }
                Ok(())
            }
            Pat::Rest(r) => self.validate_pat(&r.arg, ctx),
            Pat::Object(o) => {
                for prop in &o.props {
                    match prop {
                        ObjectPatProp::Assign(a) => {
                            if let Some(def) = &a.value {
                                self.validate_expr(def, ctx)?;
                            }
                        }
                        ObjectPatProp::KeyValue(k) => self.validate_pat(&k.value, ctx),
                        ObjectPatProp::Rest(r) => self.validate_pat(&r.arg, ctx),
                    }
                }
                Ok(())
            }
            Pat::Assign(a) => {
                self.validate_pat(&a.left, ctx)?;
                self.validate_expr(&a.right, ctx)
            }
            Pat::Invalid(_) => Ok(()),
            Pat::Expr(e) => self.validate_expr(e, ctx),
        }
    }

    /// Validate a module declaration.
    fn validate_module_decl(&self, decl: &ModuleDecl, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match decl {
            ModuleDecl::Import(i) => {
                for spec in &i.specifiers {
                    if let ImportSpecifier::TypeOnly(_) = spec {
                        // Type-only imports are fine
                    }
                }
                Ok(())
            }
            ModuleDecl::Export(e) => self.validate_export(e, ctx),
            ModuleDecl::TsImportEquals(_) => Ok(()),
            ModuleDecl::ExportDefault(_) => Ok(()),
            ModuleDecl::ExportAll(_) => Ok(()),
            ModuleDecl::ModuleASCII(_) => Ok(()),
            ModuleDecl::UseAs(_) => Ok(()),
            ModuleDecl::ImportStar(_) => Err(self.error(ctx, "Wildcard imports are forbidden.".into())),
        }
    }

    /// Validate an export.
    fn validate_export(&self, export: &ExportDecl, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match export {
            ExportDecl::Decl(d) => self.validate_decl(d, ctx),
            ExportDecl::Named(n) => {
                for spec in &n.specifiers {
                    match spec {
                        ExportSpecifier::Named(_) => {}
                        ExportSpecifier::Default(_) => {}
                        ExportSpecifier::Namespace(_) => {}
                    }
                }
                Ok(())
            }
        }
    }

    /// Validate a TypeScript type annotation.
    fn validate_ts_type(&self, type_: &TsType, ctx: &mut AnalysisContext) -> crate::Result<()> {
        match type_ {
            TsType::TsKeywordType(k) => {
                if matches!(k.kind, TsKeywordTypeKind::TsAnyType | TsKeywordTypeKind::TsUnknownType) {
                    return Err(self.error(ctx, "any and unknown are forbidden. Use concrete types.".into()));
                }
                Ok(())
            }
            TsType::TsLitType(_) => Ok(()),
            TsType::TsArrayType(a) => self.validate_ts_type(&a.elem_type, ctx),
            TsType::TsTupleType(t) => {
                for elem in &t.elem_types {
                    self.validate_ts_type(&elem.ty, ctx)?;
                }
                Ok(())
            }
            TsType::TsUnionOrIntersectionType(t) => {
                for ty in &t.types {
                    self.validate_ts_type(ty, ctx)?;
                }
                Ok(())
            }
            TsType::TsParenthesizedType(p) => self.validate_ts_type(&p.type_ann, ctx),
            TsType::TsFunctionType(f) => {
                for param in &f.params {
                    self.validate_pat(&param.pat, ctx)?;
                    if let Some(type_ann) = &param.type_ann {
                        self.validate_ts_type(&type_ann.type_ann, ctx)?;
                    }
                }
                if let Some(ret) = &f.type_ann {
                    self.validate_ts_type(&ret.type_ann, ctx)?;
                }
                Ok(())
            }
            TsType::TsConstructorType(_) => Ok(()),
            TsType::TsMappedType(_) => Err(self.error(ctx, "Mapped types are forbidden.".into())),
            TsType::TsTemplateLiteralType(_) => Ok(()),
            TsType::TsInferType(_) => Ok(()),
            TsType::TspreadType(_) => Ok(()),
            TsType::TsTypeRef(t) => {
                if let Some(type_params) = &t.type_params {
                    for param in &type_params.params {
                        self.validate_ts_type(param, ctx)?;
                    }
                }
                Ok(())
            }
            TsType::TsIndexedAccessType(i) => {
                self.validate_ts_type(&i.obj_type, ctx)?;
                self.validate_ts_type(&i.index_type, ctx)
            }
            TsType::TsTypeOperatorType(t) => self.validate_ts_type(&t.type_ann, ctx),
            TsType::TsConditionalType(c) => {
                self.validate_ts_type(&c.check_type, ctx)?;
                self.validate_ts_type(&c.extends_type, ctx)?;
                self.validate_ts_type(&c.true_type, ctx)?;
                self.validate_ts_type(&c.false_type, ctx)
            }
        }
    }

    /// Validate a TypeScript enum.
    fn validate_ts_enum(&self, e: &TsEnumDecl, ctx: &mut AnalysisContext) -> crate::Result<()> {
        // Check for duplicate members
        let mut tags: std::collections::HashSet<&str> = std::collections::HashSet::new();
        for member in &e.members {
            let tag = match &member.id {
                TsEnumMemberId::Str(s) => s.value.as_str(),
                TsEnumMemberId::Computed(c) => return Err(self.error(ctx, "Computed enum members are forbidden.".into())),
            };
            if !tags.insert(tag) {
                return Err(self.error(ctx, format!("Duplicate enum member: {}", tag)));
            }
        }
        Ok(())
    }

    /// Check for integer division warning.
    fn check_integer_division(&self, bin: &BinExpr, ctx: &mut AnalysisContext) {
        // This is a simplified check - full implementation would
        // track inferred types through the expression tree
        ctx.add_warning(
            ctx.current_location(),
            "Integer division inferred. Use explicit float (e.g., x / 2.0) if float division intended.".into(),
            "integer-division",
        );
    }

    /// Create a validation error.
    fn error(&self, ctx: &mut AnalysisContext, message: String) -> crate::RuneError {
        crate::RuneError::Analysis {
            location: ctx.current_location(),
            message,
        }
    }
}

//! # Type Inference
//!
//! Infers Rust types from TypeScript expressions.
//! Handles literals, operators, and composite types.

use swc_ecma_ast::*;
use super::{TypeInfo, TypeMap, StructInfo, EnumInfo, EnumVariant, FunctionInfo};
use super::context::AnalysisContext;

/// Infers types from TypeScript AST.
#[derive(Debug)]
pub struct TypeInferrer {
    /// Inferred types for this file
    types: TypeMap,
}

impl TypeInferrer {
    /// Create a new type inferrer.
    pub fn new() -> Self {
        Self { types: TypeMap::default() }
    }

    /// Infer all types in a module.
    pub fn infer_types(&mut self, module: &Module, ctx: &AnalysisContext) -> crate::Result<TypeMap> {
        for item in &module.body {
            self.infer_module_item(item, ctx)?;
        }
        Ok(std::mem::take(&mut self.types))
    }

    /// Infer type for a module item.
    fn infer_module_item(&mut self, item: &ModuleItem, ctx: &AnalysisContext) -> crate::Result<()> {
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.infer_decl(decl, ctx),
            _ => Ok(()),
        }
    }

    /// Infer type for a declaration.
    fn infer_decl(&mut self, decl: &Decl, ctx: &AnalysisContext) -> crate::Result<()> {
        match decl {
            Decl::Fn(f) => {
                if f.ident.sym != *"_" {
                    let info = self.infer_function_type(&f.function, ctx);
                    self.types.insert(f.ident.sym.to_string(), info);
                }
            }
            Decl::Var(v) => {
                for declarator in &v.decls {
                    self.infer_var_declarator(declarator, ctx)?;
                }
            }
            Decl::TsTypeAlias(t) => {
                let info = self.infer_ts_type(&t.type_ann, ctx);
                self.types.insert(t.id.sym.to_string(), info);
            }
            Decl::TsEnum(e) => {
                let info = self.infer_enum(e, ctx);
                self.types.insert(e.id.sym.to_string(), info);
            }
            _ => {}
        }
        Ok(())
    }

    /// Infer a variable declarator.
    fn infer_var_declarator(&mut self, declarator: &VarDeclarator, ctx: &AnalysisContext) -> crate::Result<()> {
        let name = match &declarator.name {
            Pat::Ident(ident) => ident.id.sym.to_string(),
            Pat::Object(_) | Pat::Array(_) => return Ok(()), // Destructuring - infer each part
            _ => return Ok(()),
        };

        let type_info = match &declarator.init {
            Some(init) => self.infer_expr(init, ctx)?,
            None => {
                declarator.name.as_ident().and_then(|i| i.type_ann.as_ref())
                    .map(|t| self.infer_ts_type(&t.type_ann, ctx))
                    .unwrap_or(TypeInfo::Unknown)
            }
        };

        // Check for explicit type annotation
        if let Some(Pat::Ident(ident)) = declarator.name.as_ref() {
            if let Some(type_ann) = &ident.type_ann {
                self.types.insert(name, self.infer_ts_type(&type_ann.type_ann, ctx));
                return Ok(());
            }
        }

        self.types.insert(name, type_info);
        Ok(())
    }

    /// Infer type from an expression.
    fn infer_expr(&mut self, expr: &Expr, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        match expr {
            Expr::Lit(lit) => self.infer_lit(lit),
            Expr::Ident(i) => {
                self.types.get(&i.sym.to_string()).cloned().unwrap_or(TypeInfo::Unknown)
            }
            Expr::Array(a) => {
                let elem_type = a.elems.first()
                    .map(|e| self.infer_expr(&e.as_ref().unwrap().expr, ctx))
                    .unwrap_or(Ok(TypeInfo::Unknown))?;
                Ok(TypeInfo::Array(Box::new(elem_type)))
            }
            Expr::Object(o) => {
                let fields: Vec<(String, TypeInfo)> = o.props.iter().filter_map(|p| {
                    let key = match p {
                        PropOrSpread::Prop(Prop::KeyValue(kv)) => {
                            let name = match &kv.key {
                                PropName::Str(s) => s.value.to_string(),
                                PropName::Ident(i) => i.sym.to_string(),
                                PropName::Num(n) => n.value.to_string(),
                                _ => return None,
                            };
                            let value_type = self.infer_prop(&Prop::KeyValue(kv.clone()), ctx).ok()?;
                            Some((name, value_type))
                        }
                        _ => None,
                    };
                    key
                }).collect();
                Ok(TypeInfo::Struct(StructInfo {
                    name: String::new(),
                    fields,
                }))
            }
            Expr::Bin(b) => self.infer_bin_expr(b, ctx),
            Expr::Unary(u) => self.infer_expr(&u.arg, ctx),
            Expr::Call(c) => self.infer_call(c, ctx),
            Expr::Arrow(f) => self.infer_arrow_type(f, ctx),
            Expr::Fn(f) => Ok(self.infer_function_type(&f.function, ctx)),
            Expr::Cond(c) => {
                let cons = self.infer_expr(&c.cons, ctx)?;
                let alt = self.infer_expr(&c.alt, ctx)?;
                Ok(cons) // Union of both branches
            }
            Expr::Member(m) => {
                if m.computed {
                    return Ok(TypeInfo::Unknown);
                }
                // Accessing struct field - need to look up the struct type
                self.infer_member_access(m, ctx)
            }
            Expr::Paren(p) => self.infer_expr(&p.expr, ctx),
            Expr::Tpl(t) => {
                // Template with expressions - returns string
                for expr in &t.exprs {
                    self.infer_expr(expr, ctx)?;
                }
                Ok(TypeInfo::String)
            }
            Expr::Seq(s) => {
                s.exprs.last()
                    .map(|e| self.infer_expr(e, ctx))
                    .unwrap_or(Ok(TypeInfo::Unknown))
            }
            Expr::Assign(a) => self.infer_expr(&a.value, ctx),
            Expr::Await(a) => {
                if let TypeInfo::Function(f) = self.infer_expr(&a.arg, ctx)? {
                    Ok(*f.return_type)
                } else {
                    Ok(TypeInfo::Unknown)
                }
            }
            Expr::Update(_) => Ok(TypeInfo::Float), // Post/pre increment
            Expr::TsTypeAssertion(t) => self.infer_ts_type(&t.type_ann, ctx),
            Expr::TsAs(t) => self.infer_ts_type(&t.type_ann, ctx),
            _ => Ok(TypeInfo::Unknown),
        }
    }

    /// Infer type from a literal.
    fn infer_lit(&self, lit: &Lit) -> TypeInfo {
        match lit {
            Lit::Num(n) => {
                // Check if it's an integer literal
                if n.value.fract() == 0.0 && n.value.abs() <= i32::MAX as f64 {
                    TypeInfo::Integer(n.value as i64)
                } else {
                    TypeInfo::Float
                }
            }
            Lit::Str(s) => TypeInfo::StringLiteral(s.value.to_string()),
            Lit::Bool(_) => TypeInfo::Boolean,
            Lit::Null(_) => TypeInfo::Unknown, // Null by itself is unknown
            Lit::BigInt(_) => TypeInfo::Integer(0), // i64 representation
            _ => TypeInfo::Unknown,
        }
    }

    /// Infer type from a binary expression.
    fn infer_bin_expr(&mut self, bin: &BinExpr, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        // Check if this is a Result pattern
        if let Expr::Object(obj) = &*bin.right {
            if let Some(result_type) = self.check_result_pattern(obj, ctx)? {
                return Ok(result_type);
            }
        }

        match bin.op {
            BinaryOp::Add | BinaryOp::Sub | BinaryOp::Mul | BinaryOp::Div => {
                let left = self.infer_expr(&bin.left, ctx)?;
                let right = self.infer_expr(&bin.right, ctx)?;

                // If either is Float, result is Float
                if matches!(left, TypeInfo::Float) || matches!(right, TypeInfo::Float) {
                    return Ok(TypeInfo::Float);
                }
                // If both are integers, result is integer
                if matches!(&left, TypeInfo::Integer(_)) && matches!(&right, TypeInfo::Integer(_)) {
                    return Ok(TypeInfo::Integer(0)); // Generic integer type
                }
                // String concatenation
                if matches!(left, TypeInfo::String | TypeInfo::StringLiteral(_))
                    || matches!(right, TypeInfo::String | TypeInfo::StringLiteral(_)) {
                    return Ok(TypeInfo::String);
                }
                Ok(TypeInfo::Float)
            }
            BinaryOp::EqEq | BinaryOp::NotEq
            | BinaryOp::EqEqEq | BinaryOp::NotEqEq
            | BinaryOp::Lt | BinaryOp::Le | BinaryOp::Gt | BinaryOp::Ge
            | BinaryOp::LogicalAnd | BinaryOp::LogicalOr
            | BinaryOp::BinAnd | BinaryOp::BinOr | BinaryOp::BinXor
            | BinaryOp::LShift | BinaryOp::RShift | BinaryOp::ZeroFillRShift => {
                Ok(TypeInfo::Boolean)
            }
            BinaryOp::Mod | BinaryOp::Exp | BinaryOp::NullishCoalescing => {
                Ok(TypeInfo::Float)
            }
        }
    }

    /// Check if an object pattern matches Result<T, E>.
    fn check_result_pattern(&mut self, obj: &ObjectExpr, ctx: &AnalysisContext) -> crate::Result<Option<TypeInfo>> {
        let mut has_ok = false;
        let mut has_error = false;
        let mut ok_type = TypeInfo::Unknown;
        let mut error_type = TypeInfo::Unknown;

        for prop in &obj.props {
            if let PropOrSpread::Prop(Prop::KeyValue(kv)) = prop {
                let key_name = match &kv.key {
                    PropName::Str(s) => s.value.to_string(),
                    PropName::Ident(i) => i.sym.to_string(),
                    _ => continue,
                };

                match key_name.as_str() {
                    "ok" => {
                        has_ok = true;
                        if let Expr::Member(m) = &kv.value {
                            if let Expr::Lit(Lit::True(_)) = &*m.obj {
                                ok_type = self.infer_expr(&m.prop, ctx)?;
                            }
                        } else {
                            ok_type = self.infer_expr(&kv.value, ctx)?;
                        }
                    }
                    "error" => {
                        has_error = true;
                        error_type = self.infer_expr(&kv.value, ctx)?;
                    }
                    "value" => {
                        has_ok = true;
                        ok_type = self.infer_expr(&kv.value, ctx)?;
                    }
                    _ => {}
                }
            }
        }

        if has_ok || has_error {
            Ok(Some(TypeInfo::Result(Box::new(ok_type), Box::new(error_type))))
        } else {
            Ok(None)
        }
    }

    /// Infer type from a function call.
    fn infer_call(&mut self, call: &CallExpr, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        // Check if it's a known function
        if let Expr::Ident(ident) = &*call.callee {
            if let Some(func_type) = self.types.get(&ident.sym.to_string()) {
                if let TypeInfo::Function(f) = func_type {
                    return Ok(*f.return_type.clone());
                }
            }
        }

        // Check for native imports
        if let Expr::Member(m) = &*call.callee {
            if let Expr::Ident(ident) = &*m.obj {
                if ident.sym == *"native" {
                    // Native function - return type unknown
                    return Ok(TypeInfo::Unknown);
                }
            }
        }

        // Generic unknown call
        Ok(TypeInfo::Unknown)
    }

    /// Infer arrow function type.
    fn infer_arrow_type(&mut self, arrow: &ArrowExpr, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        let params: Vec<(String, TypeInfo)> = arrow.params.iter().map(|p| {
            let name = match p.pat.as_ident() {
                Some(i) => i.id.sym.to_string(),
                None => "_".to_string(),
            };
            let type_info = p.pat.as_ident()
                .and_then(|i| i.type_ann.as_ref())
                .map(|t| self.infer_ts_type(&t.type_ann, ctx))
                .unwrap_or(TypeInfo::Unknown);
            (name, type_info)
        }).collect();

        let return_type = match &arrow.body {
            BlockStmtOrExpr::BlockStmt(b) => {
                // Look for return statements
                let mut ret_type = TypeInfo::Unknown;
                for stmt in &b.stmts {
                    if let Stmt::Return(r) = stmt {
                        if let Some(expr) = &r.value {
                            ret_type = self.infer_expr(expr, ctx)?;
                            break;
                        }
                    }
                }
                ret_type
            }
            BlockStmtOrExpr::Expr(e) => self.infer_expr(e, ctx)?,
        };

        Ok(TypeInfo::Function(FunctionInfo {
            params,
            return_type,
            is_async: arrow.is_async,
        }))
    }

    /// Infer function type from Function.
    fn infer_function_type(&mut self, func: &Function, ctx: &AnalysisContext) -> TypeInfo {
        let params: Vec<(String, TypeInfo)> = func.params.iter().map(|p| {
            let name = p.pat.as_ident()
                .map(|i| i.id.sym.to_string())
                .unwrap_or_else(|| "_".to_string());
            let type_info = p.pat.as_ident()
                .and_then(|i| i.type_ann.as_ref())
                .map(|t| self.infer_ts_type(&t.type_ann, ctx))
                .unwrap_or(TypeInfo::Unknown);
            (name, type_info)
        }).collect();

        let return_type = func.return_type.as_ref()
            .map(|t| self.infer_ts_type(&t.type_ann, ctx))
            .unwrap_or(TypeInfo::Unknown);

        TypeInfo::Function(FunctionInfo {
            params,
            return_type,
            is_async: func.is_async,
        })
    }

    /// Infer member access type.
    fn infer_member_access(&mut self, member: &MemberExpr, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        let obj_type = self.infer_expr(&member.obj, ctx)?;

        if let TypeInfo::Struct(s) = obj_type {
            let field_name = match &member.prop {
                Expr::Ident(i) => i.sym.to_string(),
                _ => return Ok(TypeInfo::Unknown),
            };
            Ok(s.fields.iter()
                .find(|(n, _)| n == &field_name)
                .map(|(_, t)| t.clone())
                .unwrap_or(TypeInfo::Unknown))
        } else {
            Ok(TypeInfo::Unknown)
        }
    }

    /// Infer type from a property.
    fn infer_prop(&self, prop: &Prop, ctx: &AnalysisContext) -> crate::Result<TypeInfo> {
        match prop {
            Prop::KeyValue(kv) => {
                let mut temp_inferrer = TypeInferrer::default();
                temp_inferrer.infer_expr(&kv.value, ctx)
            }
            _ => Ok(TypeInfo::Unknown),
        }
    }

    /// Infer type from TypeScript type annotation.
    fn infer_ts_type(&self, ts_type: &TsType, ctx: &AnalysisContext) -> TypeInfo {
        match ts_type {
            TsType::TsKeywordType(k) => match k.kind {
                TsKeywordTypeKind::TsNumberKeyword => TypeInfo::Float,
                TsKeywordTypeKind::TsStringKeyword => TypeInfo::String,
                TsKeywordTypeKind::TsBooleanKeyword => TypeInfo::Boolean,
                TsKeywordTypeKind::TsNullKeyword => TypeInfo::Unknown,
                TsKeywordTypeKind::TsUndefinedKeyword => TypeInfo::Unknown,
                TsKeywordTypeKind::TsVoidKeyword => TypeInfo::Unknown,
                TsKeywordTypeKind::TsAnyType | TsKeywordTypeKind::TsUnknownType => TypeInfo::Unknown,
                _ => TypeInfo::Unknown,
            },
            TsType::TsArrayType(a) => {
                TypeInfo::Array(Box::new(self.infer_ts_type(&a.elem_type, ctx)))
            }
            TsType::TsUnionOrIntersectionType(t) => {
                if t.ts_type_union.is_some() {
                    // Union type - could be Option or Result
                    TypeInfo::Unknown
                } else {
                    TypeInfo::Unknown
                }
            }
            TsType::TsTypeRef(t) => {
                let name = t.type_name.as_str();
                match name {
                    "Array" | "Vec" => {
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                let inner = self.infer_ts_type(&params.params[0], ctx);
                                return TypeInfo::Array(Box::new(inner));
                            }
                        }
                        TypeInfo::Array(Box::new(TypeInfo::Unknown))
                    }
                    "Option" => {
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                let inner = self.infer_ts_type(&params.params[0], ctx);
                                return TypeInfo::Option(Box::new(inner));
                            }
                        }
                        TypeInfo::Option(Box::new(TypeInfo::Unknown))
                    }
                    "Result" => {
                        if let Some(params) = &t.type_params {
                            if params.params.len() >= 2 {
                                let ok = self.infer_ts_type(&params.params[0], ctx);
                                let err = self.infer_ts_type(&params.params[1], ctx);
                                return TypeInfo::Result(Box::new(ok), Box::new(err));
                            }
                        }
                        TypeInfo::Result(Box::new(TypeInfo::Unknown), Box::new(TypeInfo::Unknown))
                    }
                    _ => TypeInfo::Unknown,
                }
            }
            TsType::TsLiteralType(l) => match &l.lit {
                TsLit::Str(s) => TypeInfo::StringLiteral(s.value.to_string()),
                TsLit::Num(n) => {
                    if n.value.fract() == 0.0 {
                        TypeInfo::Integer(n.value as i64)
                    } else {
                        TypeInfo::Float
                    }
                }
                TsLit::BigInt(b) => TypeInfo::Integer(0),
                TsLit::Boolean(b) => TypeInfo::Boolean,
            },
            TsType::TsTupleType(t) => {
                let types: Vec<TypeInfo> = t.elem_types.iter()
                    .map(|e| self.infer_ts_type(&e.ty, ctx))
                    .collect();
                TypeInfo::Struct(StructInfo {
                    name: String::new(),
                    fields: types.into_iter().enumerate()
                        .map(|(i, t)| (format!("_{}", i), t))
                        .collect(),
                })
            }
            TsType::TsParenthesizedType(p) => self.infer_ts_type(&p.type_ann, ctx),
            _ => TypeInfo::Unknown,
        }
    }

    /// Infer enum type.
    fn infer_enum(&self, e: &TsEnumDecl, _ctx: &AnalysisContext) -> TypeInfo {
        let variants: Vec<EnumVariant> = e.members.iter().map(|m| {
            let tag = match &m.id {
                TsEnumMemberId::Str(s) => s.value.to_string(),
                TsEnumMemberId::Computed(_) => String::new(),
            };
            let fields: Vec<(String, TypeInfo)> = m.init.as_ref().map(|init| {
                // Could parse the init expression to get field types
                (tag.clone(), TypeInfo::Unknown)
            }).into_iter().collect();
            EnumVariant { tag, fields }
        }).collect();

        TypeInfo::Enum(EnumInfo {
            name: e.id.sym.to_string(),
            variants,
        })
    }
}

impl Default for TypeInferrer {
    fn default() -> Self {
        Self::new()
    }
}

//! # Ownership Analysis
//!
//! Infers Rust ownership patterns from TypeScript usage.
//! Determines whether bindings should be `&T`, `&mut T`, or owned `T`.

use swc_ecma_ast::*;
use super::{BorrowMode, OwnershipAnalysis, TypeInfo};
use super::context::AnalysisContext;

/// Borrow mode for a binding.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BorrowMode {
    /// Immutable borrow `&T`
    Shared,
    /// Mutable borrow `&mut T`
    Mut,
    /// Owned value `T`
    Owned,
    /// Unknown mode
    Unknown,
}

impl BorrowMode {
    /// Check if this mode allows mutation.
    pub fn is_mutable(&self) -> bool {
        matches!(self, BorrowMode::Mut | BorrowMode::Owned)
    }

    /// Combine two borrow modes.
    pub fn combine(self, other: BorrowMode) -> BorrowMode {
        use BorrowMode::*;
        match (self, other) {
            (Unknown, m) | (m, Unknown) => m,
            (Shared, Shared) => Shared,
            (Mut, _) | (_, Mut) => Mut,
            (Owned, Owned) => Owned,
            (Shared, Owned) | (Owned, Shared) => Owned,
        }
    }
}

/// Analyzes ownership and borrowing patterns.
#[derive(Debug)]
pub struct OwnershipAnalyzer {
    /// Analysis results
    analysis: OwnershipAnalysis,
    /// Current scope's bindings
    bindings: Vec<(String, BorrowMode)>,
}

impl OwnershipAnalyzer {
    /// Create a new ownership analyzer.
    pub fn new() -> Self {
        Self {
            analysis: OwnershipAnalysis::default(),
            bindings: Vec::new(),
        }
    }

    /// Analyze a module and produce ownership information.
    pub fn analyze(&mut self, module: &Module, ctx: &AnalysisContext) -> crate::Result<OwnershipAnalysis> {
        for item in &module.body {
            self.analyze_module_item(item, ctx)?;
        }
        Ok(std::mem::take(&mut self.analysis))
    }

    /// Analyze a module item.
    fn analyze_module_item(&mut self, item: &ModuleItem, ctx: &AnalysisContext) -> crate::Result<()> {
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.analyze_decl(decl, ctx),
            _ => Ok(()),
        }
    }

    /// Analyze a declaration.
    fn analyze_decl(&mut self, decl: &Decl, ctx: &AnalysisContext) -> crate::Result<()> {
        match decl {
            Decl::Fn(f) => {
                // Analyze function body
                if let Some(body) = f.function.body.as_ref() {
                    self.push_scope();
                    // Add parameters as bindings
                    for param in &f.function.params {
                        let name = param.pat.as_ident()
                            .map(|i| i.id.sym.to_string())
                            .unwrap_or_else(|| "_".to_string());
                        self.bindings.push((name.clone(), BorrowMode::Unknown));
                    }
                    self.analyze_stmt(body, ctx)?;
                    self.pop_scope();
                }
            }
            Decl::Var(v) => {
                for declarator in &v.decls {
                    let (name, mode) = self.analyze_var_declarator(declarator, ctx)?;
                    self.analysis.set(name, mode);
                }
            }
            _ => {}
        }
        Ok(())
    }

    /// Analyze a variable declarator.
    fn analyze_var_declarator(&mut self, declarator: &VarDeclarator, ctx: &AnalysisContext) -> crate::Result<(String, BorrowMode)> {
        let name = match &declarator.name {
            Pat::Ident(ident) => ident.id.sym.to_string(),
            _ => return Ok((String::new(), BorrowMode::Unknown)),
        };

        let mode = match &declarator.init {
            Some(init) => self.analyze_expr_usage(init, ctx)?,
            None => BorrowMode::Owned,
        };

        self.bindings.push((name.clone(), mode));
        Ok((name, mode))
    }

    /// Analyze expression and infer borrow mode from usage.
    fn analyze_expr_usage(&mut self, expr: &Expr, ctx: &AnalysisContext) -> crate::Result<BorrowMode> {
        match expr {
            Expr::Ident(i) => {
                // Look up the binding
                self.find_binding(&i.sym.to_string())
                    .map(|(_, m)| *m)
                    .unwrap_or(BorrowMode::Unknown)
            }
            Expr::Call(c) => {
                // Check if it's a consuming call
                for arg in &c.args {
                    self.analyze_expr_usage(&arg.expr, ctx)?;
                }
                // Return value from function call is typically owned
                BorrowMode::Owned
            }
            Expr::Member(m) => {
                // Accessing a member typically needs shared reference
                self.analyze_expr_usage(&m.obj, ctx)?;
                BorrowMode::Shared
            }
            Expr::Bin(b) => {
                self.analyze_expr_usage(&b.left, ctx)?;
                self.analyze_expr_usage(&b.right, ctx)?;
                BorrowMode::Owned
            }
            Expr::Object(o) => {
                for prop in &o.props {
                    if let PropOrSpread::Prop(Prop::KeyValue(kv)) = prop {
                        self.analyze_expr_usage(&kv.value, ctx)?;
                    }
                }
                BorrowMode::Owned
            }
            Expr::Array(a) => {
                for elem in &a.elems {
                    if let Some(e) = elem {
                        self.analyze_expr_usage(&e.expr, ctx)?;
                    }
                }
                BorrowMode::Owned
            }
            Expr::Arrow(a) => {
                if let BlockStmtOrExpr::BlockStmt(b) = &a.body {
                    self.push_scope();
                    for param in &a.params {
                        let name = param.pat.as_ident()
                            .map(|i| i.id.sym.to_string())
                            .unwrap_or_else(|| "_".to_string());
                        self.bindings.push((name.clone(), BorrowMode::Unknown));
                    }
                    for stmt in &b.stmts {
                        self.analyze_stmt(stmt, ctx)?;
                    }
                    self.pop_scope();
                }
                BorrowMode::Owned
            }
            _ => BorrowMode::Owned,
        }
    }

    /// Analyze a statement for ownership patterns.
    fn analyze_stmt(&mut self, stmt: &Stmt, ctx: &AnalysisContext) -> crate::Result<()> {
        match stmt {
            Stmt::Expr(e) => {
                self.analyze_expr_usage(&e.expr, ctx)?;
            }
            Stmt::If(i) => {
                self.analyze_expr_usage(&i.test, ctx)?;
                self.analyze_stmt(&i.cons, ctx)?;
                if let Some(alt) = &i.alt {
                    self.analyze_stmt(alt, ctx)?;
                }
            }
            Stmt::While(w) => {
                self.analyze_expr_usage(&w.test, ctx)?;
                self.analyze_stmt(&w.body, ctx)
            }
            Stmt::For(f) => {
                if let Some(init) = &f.init {
                    match init {
                        VarDeclOrExpr::VarDecl(v) => {
                            for decl in &v.decls {
                                let (name, mode) = self.analyze_var_declarator(decl, ctx)?;
                                self.analysis.set(name, mode);
                            }
                        }
                        VarDeclOrExpr::Expr(e) => {
                            self.analyze_expr_usage(e, ctx)?;
                        }
                    }
                }
                if let Some(test) = &f.test {
                    self.analyze_expr_usage(test, ctx)?;
                }
                if let Some(update) = &f.update {
                    self.analyze_expr_usage(update, ctx)?;
                }
                self.analyze_stmt(&f.body, ctx)
            }
            Stmt::ForOf(f) => {
                self.push_scope();
                let item_name = match &f.left {
                    VarDeclOrPat::VarDecl(v) => {
                        v.decls.first().and_then(|d| d.name.as_ident())
                            .map(|i| i.id.sym.to_string())
                    }
                    VarDeclOrPat::Pat(p) => {
                        p.as_ident().map(|i| i.id.sym.to_string())
                    }
                    _ => None,
                };
                self.analyze_expr_usage(&f.right, ctx)?;
                if let Some(name) = item_name {
                    self.bindings.push((name.clone(), BorrowMode::Shared));
                    self.analysis.set(name, BorrowMode::Shared);
                }
                self.analyze_stmt(&f.body, ctx)?;
                self.pop_scope()
            }
            Stmt::DoWhile(d) => {
                self.analyze_stmt(&d.body, ctx)?;
                self.analyze_expr_usage(&d.test, ctx)
            }
            Stmt::Switch(s) => {
                self.analyze_expr_usage(&s.discriminant, ctx)?;
                for case in &s.cases {
                    for item in &case.cons {
                        self.analyze_stmt(item, ctx)?;
                    }
                }
                Ok(())
            }
            Stmt::Block(b) => {
                self.push_scope();
                for stmt in &b.stmts {
                    self.analyze_stmt(stmt, ctx)?;
                }
                self.pop_scope();
                Ok(())
            }
            Stmt::Return(r) => {
                if let Some(expr) = &r.value {
                    self.analyze_expr_usage(expr, ctx)?;
                }
                Ok(())
            }
            Stmt::Break(_) | Stmt::Continue(_) | Stmt::Empty(_) | Stmt::Debugger(_) => Ok(()),
            Stmt::Labeled(l) => self.analyze_stmt(&l.body, ctx),
            Stmt::With(_) => Ok(()), // Forbidden - caught by validator
            Stmt::Try(_) | Stmt::Throw(_) => Ok(()), // Forbidden - caught by validator
            Stmt::Decl(d) => self.analyze_decl(d, ctx),
        }
    }

    /// Find a binding in the current scope chain.
    fn find_binding(&self, name: &str) -> Option<&(String, BorrowMode)> {
        self.bindings.iter().rev().find(|(n, _)| n == name)
    }

    /// Push a new scope.
    fn push_scope(&mut self) {
        let depth = self.bindings.len();
        self.bindings.push((format!("__scope_{}", depth), BorrowMode::Unknown));
    }

    /// Pop the current scope.
    fn pop_scope(&mut self) {
        while let Some((name, _)) = self.bindings.pop() {
            if name.starts_with("__scope_") {
                break;
            }
        }
    }
}

impl Default for OwnershipAnalyzer {
    fn default() -> Self {
        Self::new()
    }
}

//! # Analysis Context
//!
//! Maintains state during analysis including source location tracking
//! and warning accumulation.

use crate::parser::SourceFile;
use super::TypeInfo;

/// Context for type and ownership analysis.
#[derive(Debug)]
pub struct AnalysisContext {
    /// Source file being analyzed
    source: SourceFile,
    /// Current line being processed
    current_line: u32,
    /// Current column being processed
    current_column: u32,
    /// Accumulated warnings
    warnings: Vec<super::AnalysisWarning>,
    /// Inferred types cache
    type_cache: std::collections::HashMap<String, TypeInfo>,
}

impl AnalysisContext {
    /// Create a new analysis context.
    pub fn new(source: &SourceFile) -> Self {
        Self {
            source: source.clone(),
            current_line: 1,
            current_column: 1,
            warnings: Vec::new(),
            type_cache: std::collections::HashMap::new(),
        }
    }

    /// Get the current source location as a string.
    pub fn current_location(&self) -> String {
        format!("{}:{}:{}", self.source.path.display(), self.current_line, self.current_column)
    }

    /// Update current location from a span.
    pub fn update_location(&mut self, span: &swc_common::Span) {
        let (line, col) = self.source.location_from_offset(span.lo.0);
        self.current_line = line;
        self.current_column = col;
    }

    /// Add a warning.
    pub fn add_warning(&mut self, location: String, message: String, code: &'static str) {
        self.warnings.push(super::AnalysisWarning {
            location,
            message,
            code,
        });
    }

    /// Take all warnings.
    pub fn take_warnings(&mut self) -> Vec<super::AnalysisWarning> {
        std::mem::take(&mut self.warnings)
    }

    /// Get inferred type for a name.
    pub fn infer_type(&self, _expr: &swc_ecma_ast::Expr) -> Option<TypeInfo> {
        // Would need to walk the expression tree to determine type
        None
    }

    /// Check if a string is a reserved Rust keyword.
    pub fn is_rust_keyword(&self, s: &str) -> bool {
        matches!(
            s,
            "as" | "async" | "await" | "break" | "const" | "continue" | "crate" | "dyn"
            | "else" | "enum" | "extern" | "false" | "fn" | "for" | "if" | "impl"
            | "in" | "let" | "loop" | "match" | "mod" | "move" | "mut" | "pub"
            | "ref" | "return" | "self" | "Self" | "static" | "struct" | "super"
            | "trait" | "true" | "type" | "unsafe" | "use" | "where" | "while"
        )
    }

    /// Mangle a name to avoid Rust keyword conflicts.
    pub fn mangle_name(&self, name: &str) -> String {
        if self.is_rust_keyword(name) {
            format!("{}_rune", name)
        } else {
            name.to_string()
        }
    }

    /// Get source file path.
    pub fn source_path(&self) -> &std::path::Path {
        &self.source.path
    }

    /// Get the raw source text.
    pub fn source_text(&self) -> &str {
        &self.source.source
    }
}

//! # Code Generator
//!
//! Transpiles TypeScript AST to Rust source code.
//! Handles type mapping, JSX transformation, and code emission.

mod emitter;
mod types;
mod jsx;

pub use emitter::{RustEmitter, EmitOptions};
pub use types::TypeEmitter;
pub use jsx::JsxTranspiler;

/// Options for code generation.
#[derive(Debug, Clone)]
pub struct CodegenOptions {
    /// Generate debug info
    pub debug: bool,
    /// Target Rust edition
    pub edition: String,
    /// Enable hot reload mode
    pub hot_reload: bool,
}

impl Default for CodegenOptions {
    fn default() -> Self {
        Self {
            debug: false,
            edition: "2021".to_string(),
            hot_reload: false,
        }
    }
}

/// Generated Rust module.
#[derive(Debug, Clone)]
pub struct GeneratedModule {
    /// Module name (file stem)
    pub name: String,
    /// Generated Rust source code
    pub source: String,
    /// Imports required by this module
    pub imports: Vec<Import>,
}

/// An import statement.
#[derive(Debug, Clone)]
pub struct Import {
    /// Import path
    pub path: String,
    /// Imported names
    pub names: Vec<ImportedName>,
    /// Is this a native import?
    pub is_native: bool,
}

/// A single imported name.
#[derive(Debug, Clone)]
pub struct ImportedName {
    /// Original name in TypeScript
    pub original: String,
    /// Name to use in Rust
    pub rust_name: String,
}

/// Generate Rust code from analyzed source.
pub fn generate(
    source: &crate::parser::SourceFile,
    analysis: &crate::analyzer::AnalysisResult,
) -> crate::Result<GeneratedModule> {
    let emitter = RustEmitter::new(source, analysis);
    emitter.emit()
}

//! # Rust Emitter
//!
//! Core transpilation from TypeScript AST to Rust source.

use std::collections::HashMap;
use swc_ecma_ast::*;
use crate::{parser::SourceFile, analyzer::{AnalysisResult, TypeInfo, BorrowMode}};
use super::{GeneratedModule, Import, ImportedName, CodegenOptions};

/// Options for code emission.
#[derive(Debug, Clone)]
pub struct EmitOptions {
    /// Generate source maps
    pub source_map: bool,
    /// Pretty print output
    pub pretty: bool,
}

impl Default for EmitOptions {
    fn default() -> Self {
        Self {
            source_map: false,
            pretty: true,
        }
    }
}

/// Emits Rust code from TypeScript AST.
pub struct RustEmitter<'a> {
    source: &'a SourceFile,
    analysis: &'a AnalysisResult,
    imports: Vec<Import>,
    output: String,
    indent: usize,
    options: EmitOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            options: EmitOptions::default(),
        }
    }

    /// Emit the complete module.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        self.write_header()?;
        self.emit_module_items()?;
        self.write_footer()?;

        let name = self.source.path.file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
        })
    }

    /// Write module header.
    fn write_header(&mut self) -> crate::Result<()> {
        self.push_line("use std::collections::HashMap;");
        self.push_line("use std::fmt::{self, Write};");
        self.push_line("");
        Ok(())
    }

    /// Write module footer.
    fn write_footer(&mut self) -> crate::Result<()> {
        // Footer if needed
        Ok(())
    }

    /// Emit all module items.
    fn emit_module_items(&mut self) -> crate::Result<()> {
        for item in &self.source.module.body {
            self.emit_module_item(item)?;
            self.push_line("");
        }
        Ok(())
    }

    /// Emit a single module item.
    fn emit_module_item(&mut self, item: &ModuleItem) -> crate::Result<()> {
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.emit_decl(decl),
            ModuleItem::ModuleDecl(decl) => self.emit_module_decl(decl),
            ModuleItem::Stmt(stmt) => self.emit_stmt(stmt),
            _ => Ok(()),
        }
    }

    /// Emit a declaration.
    fn emit_decl(&mut self, decl: &Decl) -> crate::Result<()> {
        match decl {
            Decl::Fn(f) => self.emit_fn(f),
            Decl::Var(v) => self.emit_var_decl(v),
            Decl::TsTypeAlias(t) => self.emit_type_alias(t),
            Decl::TsEnum(e) => self.emit_enum(e),
            Decl::TsInterface(i) => self.emit_interface(i),
            _ => Ok(()),
        }
    }

    /// Emit a function.
    fn emit_fn(&mut self, f: &FnDecl) -> crate::Result<()> {
        let name = self.mangle(&f.ident.sym.to_string());

        // Determine async
        if f.function.is_async {
            self.push("pub async ");
        } else {
            self.push("pub ");
        }

        // Function name
        self.push(format!("fn {name}("));

        // Parameters
        for (i, param) in f.function.params.iter().enumerate() {
            if i > 0 {
                self.push(", ");
            }
            self.emit_fn_param(param)?;
        }
        self.push(")");

        // Return type
        if let Some(ret) = &f.function.return_type {
            self.push(" -> ");
            self.emit_type(&ret.type_ann)?;
        }

        // Body
        if let Some(body) = &f.function.body {
            self.push(" ");
            self.emit_block_stmt(body)?;
        } else {
            self.push(";")?;
        }

        Ok(())
    }

    /// Emit function parameters.
    fn emit_fn_param(&mut self, param: &Param) -> crate::Result<()> {
        let name = param.pat.as_ident()
            .map(|i| self.mangle(&i.id.sym.to_string()))
            .unwrap_or_else(|| "_".to_string());

        // Determine borrow mode
        let mode = self.analysis.ownership.get(&name).copied().unwrap_or(BorrowMode::Unknown);
        let prefix = match mode {
            BorrowMode::Mut => "&mut ",
            BorrowMode::Shared => "&",
            BorrowMode::Owned => "",
            BorrowMode::Unknown => "",
        };

        // Type annotation
        if let Some(type_ann) = param.pat.as_ident().and_then(|i| i.type_ann.as_ref()) {
            self.push(format!("{prefix}{name}: "));
            self.emit_type(&type_ann.type_ann)?;
        } else {
            self.push(format!("{prefix}{name}"));
        }

        Ok(())
    }

    /// Emit a block statement.
    fn emit_block_stmt(&mut self, block: &BlockStmt) -> crate::Result<()> {
        self.push_line("{")?;
        self.indent += 1;
        for stmt in &block.stmts {
            self.emit_stmt(stmt)?;
            if !matches!(stmt, Stmt::Empty(_)) {
                self.push_line(";")?;
            }
        }
        self.indent -= 1;
        self.push("}")?;
        Ok(())
    }

    /// Emit a statement.
    fn emit_stmt(&mut self, stmt: &Stmt) -> crate::Result<()> {
        self.push_indent();
        match stmt {
            Stmt::Expr(e) => self.emit_expr(&e.expr)?,
            Stmt::If(i) => self.emit_if(i)?,
            Stmt::While(w) => self.emit_while(w)?,
            Stmt::For(f) => self.emit_for(f)?,
            Stmt::ForOf(f) => self.emit_for_of(f)?,
            Stmt::DoWhile(d) => self.emit_do_while(d)?,
            Stmt::Switch(s) => self.emit_switch(s)?,
            Stmt::Block(b) => self.emit_block_stmt(b)?,
            Stmt::Return(r) => self.emit_return(r)?,
            Stmt::Break(_) => self.push("break")?,
            Stmt::Continue(_) => self.push("continue")?,
            Stmt::Empty(_) => self.push("/* empty */")?,
            Stmt::Debugger(_) => self.push("unimplemented!()")?,
            Stmt::Labeled(l) => {
                self.push(format!("{}: ", l.label.sym));
                self.emit_stmt(&l.body)?;
            }
            Stmt::Decl(d) => self.emit_decl(d)?,
            Stmt::Try(_) | Stmt::Throw(_) | Stmt::With(_) => {
                self.push("unreachable!()")?;
            }
        }
        Ok(())
    }

    /// Emit a variable declaration.
    fn emit_var_decl(&mut self, v: &VarDecl) -> crate::Result<()> {
        let keyword = match v.kind {
            VarDeclKind::Const => "let",
            VarDeclKind::Let => "let mut",
            VarDeclKind::Var => "let mut",
        };

        for (i, decl) in v.decls.iter().enumerate() {
            if i > 0 {
                self.push_line(";")?;
                self.push_indent();
            }
            self.push(format!("{} ", keyword));
            self.emit_pat(&decl.name)?;
            if let Some(init) = &decl.init {
                self.push(" = ");
                self.emit_expr(init)?;
            }
        }
        Ok(())
    }

    /// Emit a pattern.
    fn emit_pat(&mut self, pat: &Pat) -> crate::Result<()> {
        match pat {
            Pat::Ident(i) => {
                let name = self.mangle(&i.id.sym.to_string());
                self.push(name);
                if let Some(type_ann) = &i.type_ann {
                    self.push(": ");
                    self.emit_type(&type_ann.type_ann)?;
                }
            }
            Pat::Array(a) => {
                self.push("[");
                for (i, elem) in a.elems.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    if let Some(p) = elem {
                        self.emit_pat(p)?;
                    }
                }
                self.push("]");
            }
            Pat::Object(o) => {
                self.push("{");
                for (i, prop) in o.props.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    match prop {
                        ObjectPatProp::Assign(a) => {
                            self.push(&a.key.sym.to_string());
                            if let Some(v) = &a.value {
                                self.push(" = ");
                                self.emit_expr(&Expr::Paren(ParenExpr {
                                    span: Default::default(),
                                    expr: Box::new(v.clone()),
                                }))?;
                            }
                        }
                        ObjectPatProp::KeyValue(kv) => {
                            self.emit_expr(&Expr::Ident(kv.key.clone().into()))?;
                            self.push(": ");
                            self.emit_pat(&kv.value)?;
                        }
                        ObjectPatProp::Rest(r) => {
                            self.push("..");
                            self.emit_pat(&r.arg)?;
                        }
                    }
                }
                self.push("}");
            }
            Pat::Rest(r) => {
                self.push("..");
                self.emit_pat(&r.arg)?;
            }
            Pat::Assign(a) => {
                self.emit_pat(&a.left)?;
                self.push(" = ");
                self.emit_expr(&a.right)?;
            }
            _ => self.push("_"),
        }
        Ok(())
    }

    /// Emit an expression.
    fn emit_expr(&mut self, expr: &Expr) -> crate::Result<()> {
        match expr {
            Expr::Lit(l) => self.emit_lit(l)?,
            Expr::Ident(i) => {
                let name = self.mangle(&i.sym.to_string());
                self.push(name);
            }
            Expr::Bin(b) => self.emit_bin_expr(b)?,
            Expr::Unary(u) => self.emit_unary(u)?,
            Expr::Update(u) => self.emit_update(u)?,
            Expr::Assign(a) => self.emit_assign(a)?,
            Expr::Member(m) => self.emit_member(m)?,
            Expr::Call(c) => self.emit_call(c)?,
            Expr::Arrow(a) => self.emit_arrow(a)?,
            Expr::Fn(f) => self.emit_fn_expr(f)?,
            Expr::Cond(c) => self.emit_cond(c)?,
            Expr::Array(a) => self.emit_array(a)?,
            Expr::Object(o) => self.emit_object(o)?,
            Expr::Paren(p) => {
                self.push("(");
                self.emit_expr(&p.expr)?;
                self.push(")");
            }
            Expr::Seq(s) => {
                for (i, e) in s.exprs.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    self.emit_expr(e)?;
                }
            }
            Expr::Tpl(t) => self.emit_tpl(t)?,
            Expr::TaggedTpl(t) => {
                self.emit_expr(&t.tag)?;
                self.emit_tpl(&t.tpl)?;
            }
            Expr::Await(a) => {
                self.push("(");
                self.push("async { ");
                self.emit_expr(&a.arg)?;
                self.push(".await");
                self.push(" })()");
            }
            Expr::TsTypeAssertion(t) => self.emit_expr(&t.expr)?,
            Expr::TsAs(t) => {
                // Type assertion - emit expression, type is for reference
                self.emit_expr(&t.expr)?;
            }
            Expr::TsNonNull(t) => self.emit_expr(&t.expr)?,
            Expr::TsSatisfies(t) => self.emit_expr(&t.expr)?,
            Expr::This(_) => self.push("/* this */ unimplemented!()")?,
            Expr::Super(_) => self.push("unimplemented!()")?,
            Expr::New(n) => self.emit_call(&CallExpr {
                span: n.span,
                callee: Box::new(Expr::Ident(Ident {
                    span: Default::default(),
                    sym: n.callee.value.as_str().into(),
                    optional: false,
                })),
                args: n.args.clone(),
                type_args: None,
            })?,
            Expr::Class(_) => self.push("unimplemented!() /* class */")?,
            Expr::Yield(_) => self.push("unimplemented!() /* yield */")?,
            Expr::MetaProp(_) => self.push("unimplemented!()")?,
            Expr::Invalid(_) => self.push("unreachable!()")?,
            Expr::Jsx(j) => self.emit_jsx(j)?,
        }
        Ok(())
    }

    /// Emit a literal.
    fn emit_lit(&mut self, lit: &Lit) -> crate::Result<()> {
        match lit {
            Lit::Null(_) => self.push("()"),
            Lit::Bool(b) => self.push(if b.value { "true" } else { "false" }),
            Lit::Num(n) => {
                if n.value.fract() == 0.0 {
                    self.push(format!("{}", n.value as i32));
                } else {
                    self.push(format!("{}", n.value));
                }
            }
            Lit::Str(s) => self.push(format!("{:?}", s.value)),
            Lit::BigInt(b) => self.push(format!("{}i64", b.value)),
            Lit::Regex(_) => self.push("Regex::new(\"...\").unwrap()")?,
            Lit::JSXText(t) => self.push(format!("{:?}", t.value)),
        }
        Ok(())
    }

    /// Emit a binary expression.
    fn emit_bin_expr(&mut self, bin: &BinExpr) -> crate::Result<()> {
        let rust_op = match bin.op {
            BinaryOp::Add => "+",
            BinaryOp::Sub => "-",
            BinaryOp::Mul => "*",
            BinaryOp::Div => "/",
            BinaryOp::Mod => "%",
            BinaryOp::EqEq | BinaryOp::EqEqEq => "==",
            BinaryOp::NotEq | BinaryOp::NotEqEq => "!=",
            BinaryOp::Lt => "<",
            BinaryOp::Le => "<=",
            BinaryOp::Gt => ">",
            BinaryOp::Ge => ">=",
            BinaryOp::LogicalAnd => "&&",
            BinaryOp::LogicalOr => "||",
            BinaryOp::BinAnd => "&",
            BinaryOp::BinOr => "|",
            BinaryOp::BinXor => "^",
            BinaryOp::LShift => "<<",
            BinaryOp::RShift => ">>",
            BinaryOp::ZeroFillRShift => ">>",
            BinaryOp::Exp => "f64::powf",
            BinaryOp::NullishCoalescing => "unwrap_or",
        };

        if bin.op == BinaryOp::Exp {
            self.push("f64::powf(")?;
            self.emit_expr(&bin.left)?;
            self.push(", ")?;
            self.emit_expr(&bin.right)?;
            self.push(")")?;
            return Ok(());
        }

        if bin.op == BinaryOp::NullishCoalescing {
            self.emit_expr(&bin.left)?;
            self.push(".unwrap_or(")?;
            self.emit_expr(&bin.right)?;
            self.push(")")?;
            return Ok(());
        }

        self.push("(")?;
        self.emit_expr(&bin.left)?;
        self.push(format!(" {} ", rust_op))?;
        self.emit_expr(&bin.right)?;
        self.push(")")?;
        Ok(())
    }

    /// Emit a unary expression.
    fn emit_unary(&mut self, u: &UnaryExpr) -> crate::Result<()> {
        let rust_op = match u.op {
            UnaryOp::Minus => "-",
            UnaryOp::Plus => "",
            UnaryOp::Bang => "!",
            UnaryOp::Tilde => "!",
            UnaryOp::TypeOf => "/* typeof */ unimplemented!()",
            UnaryOp::Void => "()",
        };

        if u.op == UnaryOp::TypeOf {
            self.push(rust_op)?;
            return Ok(());
        }

        if u.op == UnaryOp::Void {
            self.push("()")?;
            return Ok(());
        }

        self.push(rust_op)?;
        self.emit_expr(&u.arg)?;
        Ok(())
    }

    /// Emit an update expression.
    fn emit_update(&mut self, u: &UpdateExpr) -> crate::Result<()> {
        let op = if u.is_prefix { 
            match u.op {
                UpdateOp::PlusPlus => "++",
                UpdateOp::MinusMinus => "--",
            }
        } else {
            match u.op {
                UpdateOp::PlusPlus => "++",
                UpdateOp::MinusMinus => "--",
            }
        };

        if u.is_prefix {
            self.push(op)?;
            self.emit_expr(&u.arg)?;
        } else {
            self.emit_expr(&u.arg)?;
            self.push(op)?;
        }
        Ok(())
    }

    /// Emit an assignment expression.
    fn emit_assign(&mut self, a: &AssignExpr) -> crate::Result<()> {
        let rust_op = match a.op {
            AssignOp::Assign => "=",
            AssignOp::AddAssign => "+=",
            AssignOp::SubAssign => "-=",
            AssignOp::MulAssign => "*=",
            AssignOp::DivAssign => "/=",
            AssignOp::ModAssign => "%=",
            _ => "=",
        };

        self.emit_expr(&a.left)?;
        self.push(format!(" {} ", rust_op))?;
        self.emit_expr(&a.value)?;
        Ok(())
    }

    /// Emit a member expression.
    fn emit_member(&mut self, m: &MemberExpr) -> crate::Result<()> {
        self.emit_expr(&m.obj)?;

        if m.computed {
            self.push("[")?;
            self.emit_expr(&m.prop)?;
            self.push("]")?;
        } else {
            self.push(".")?;
            match &m.prop {
                Expr::Ident(i) => self.push(&i.sym.to_string()),
                _ => self.emit_expr(&m.prop)?,
            }
        }
        Ok(())
    }

    /// Emit a call expression.
    fn emit_call(&mut self, c: &CallExpr) -> crate::Result<()> {
        self.emit_expr(&c.callee)?;
        self.push("(")?;
        for (i, arg) in c.args.iter().enumerate() {
            if i > 0 { self.push(", "); }
            self.emit_expr(&arg.expr)?;
        }
        self.push(")")?;
        Ok(())
    }

    /// Emit an arrow function.
    fn emit_arrow(&mut self, a: &ArrowExpr) -> crate::Result<()> {
        // Collect parameter names
        let params: Vec<String> = a.params.iter().filter_map(|p| {
            p.pat.as_ident().map(|i| self.mangle(&i.id.sym.to_string()))
        }).collect();

        if a.is_async {
            self.push("async { |")?;
        } else {
            self.push("|| {")?;
        }
        self.push(params.join(", "));
        self.push("| ")?;

        match &a.body {
            BlockStmtOrExpr::BlockStmt(b) => {
                for stmt in &b.stmts {
                    self.emit_stmt(stmt)?;
                    self.push_line(";")?;
                }
            }
            BlockStmtOrExpr::Expr(e) => {
                self.push("(")?;
                self.emit_expr(e)?;
                self.push(")")?;
            }
        }

        self.push("}")?;
        Ok(())
    }

    /// Emit a function expression.
    fn emit_fn_expr(&mut self, f: &FnExpr) -> crate::Result<()> {
        self.push("|")?;
        let params: Vec<String> = f.function.params.iter().filter_map(|p| {
            p.pat.as_ident().map(|i| self.mangle(&i.id.sym.to_string()))
        }).collect();
        self.push(params.join(", "));
        self.push("| ")?;

        if let Some(body) = &f.function.body {
            self.emit_block_stmt(body)?;
        }
        Ok(())
    }

    /// Emit a conditional expression.
    fn emit_cond(&mut self, c: &CondExpr) -> crate::Result<()> {
        self.emit_expr(&c.test)?;
        self.push(" ? ")?;
        self.emit_expr(&c.cons)?;
        self.push(" : ")?;
        self.emit_expr(&c.alt)?;
        Ok(())
    }

    /// Emit an array literal.
    fn emit_array(&mut self, a: &ArrayExpr) -> crate::Result<()> {
        self.push("vec![")?;
        for (i, elem) in a.elems.iter().enumerate() {
            if i > 0 { self.push(", "); }
            if let Some(e) = elem {
                self.emit_expr(&e.expr)?;
            }
        }
        self.push("]")?;
        Ok(())
    }

    /// Emit an object literal.
    fn emit_object(&mut self, o: &ObjectExpr) -> crate::Result<()> {
        self.push("__rune_obj!({")?;
        for (i, prop) in o.props.iter().enumerate() {
            if i > 0 { self.push(", "); }
            match prop {
                PropOrSpread::Prop(p) => self.emit_prop(p)?,
                PropOrSpread::Spread(s) => {
                    self.push("..")?;
                    self.emit_expr(&s.expr)?;
                }
            }
        }
        self.push("})")?;
        Ok(())
    }

    /// Emit a property.
    fn emit_prop(&mut self, prop: &Prop) -> crate::Result<()> {
        match prop {
            Prop::Shorthand(i) => self.push(&self.mangle(&i.sym.to_string())),
            Prop::KeyValue(kv) => {
                // Key
                match &kv.key {
                    PropName::Str(s) => self.push(format!("{:?}: ", s.value)),
                    PropName::Ident(i) => self.push(format!("{}: ", i.sym)),
                    PropName::Num(n) => self.push(format!("{}: ", n.value)),
                    PropName::Computed(c) => {
                        self.push("[")?;
                        self.emit_expr(&c.expr)?;
                        self.push("]: ")?;
                    }
                    _ => {}
                }
                // Value
                self.emit_expr(&kv.value)?;
            }
            Prop::Assign(a) => {
                self.push(&self.mangle(&a.key.sym.to_string()))?;
                self.push(" = ")?;
                self.emit_expr(&a.value)?;
            }
            Prop::Getter(g) => {
                self.push("get ")?;
                if let PropName::Ident(i) = &g.key {
                    self.push(&i.sym.to_string());
                }
                self.push("() ")?;
                if let Some(body) = &g.body {
                    self.emit_block_stmt(body)?;
                }
            }
            Prop::Setter(s) => {
                self.push("set ")?;
                if let PropName::Ident(i) = &s.key {
                    self.push(&i.sym.to_string());
                }
                self.push("(")?;
                if let Some(param) = &s.param {
                    self.emit_pat(param)?;
                }
                self.push(") ")?;
                if let Some(body) = &s.body {
                    self.emit_block_stmt(body)?;
                }
            }
            Prop::Method(m) => {
                if let PropName::Ident(i) = &m.key {
                    self.push(&i.sym.to_string());
                }
                self.push("(")?;
                // Parameters
                self.push(") ")?;
                if let Some(body) = &m.function.body {
                    self.emit_block_stmt(body)?;
                }
            }
        }
        Ok(())
    }

    /// Emit a template literal.
    fn emit_tpl(&mut self, t: &TplExpr) -> crate::Result<()> {
        self.push("format!(\"")?;
        for (i, part) in t.quasis.iter().enumerate() {
            self.push(&part.raw.value.to_string().replace("{", "{{").replace("}", "}}"));
            if i < t.exprs.len() {
                self.push("{}")?;
            }
        }
        self.push("\", ")?;
        for (i, expr) in t.exprs.iter().enumerate() {
            if i > 0 { self.push(", "); }
            self.emit_expr(expr)?;
        }
        self.push(")")?;
        Ok(())
    }

    /// Emit an if statement.
    fn emit_if(&mut self, i: &IfStmt) -> crate::Result<()> {
        self.push("if ")?;
        self.emit_expr(&i.test)?;
        self.push(" ")?;
        self.emit_stmt(&i.cons)?;
        if let Some(alt) = &i.alt {
            self.push(" else ")?;
            self.emit_stmt(alt)?;
        }
        Ok(())
    }

    /// Emit a while loop.
    fn emit_while(&mut self, w: &WhileStmt) -> crate::Result<()> {
        self.push("while ")?;
        self.emit_expr(&w.test)?;
        self.push(" ")?;
        self.emit_stmt(&w.body)?;
        Ok(())
    }

    /// Emit a for loop.
    fn emit_for(&mut self, f: &ForStmt) -> crate::Result<()> {
        self.push("for ")?;
        if let Some(init) = &f.init {
            match init {
                VarDeclOrExpr::VarDecl(v) => {
                    self.emit_var_decl(v)?;
                }
                VarDeclOrExpr::Expr(e) => {
                    self.emit_expr(e)?;
                }
            }
        }
        if let Some(test) = &f.test {
            self.emit_expr(test)?;
        }
        self.push("; ")?;
        if let Some(update) = &f.update {
            self.emit_expr(update)?;
        }
        self.push(" ")?;
        self.emit_stmt(&f.body)?;
        Ok(())
    }

    /// Emit a for-of loop.
    fn emit_for_of(&mut self, f: &ForOfStmt) -> crate::Result<()> {
        self.push("for ")?;
        self.emit_expr(&f.left)?;
        self.push(" in ")?;
        self.emit_expr(&f.right)?;
        self.push(" ")?;
        self.emit_stmt(&f.body)?;
        Ok(())
    }

    /// Emit a do-while loop.
    fn emit_do_while(&mut self, d: &DoWhileStmt) -> crate::Result<()> {
        self.push("loop { ")?;
        self.emit_stmt(&d.body)?;
        self.push("if !(")?;
        self.emit_expr(&d.test)?;
        self.push(") { break; } }")?;
        Ok(())
    }

    /// Emit a switch statement.
    fn emit_switch(&mut self, s: &SwitchStmt) -> crate::Result<()> {
        self.push("match ")?;
        self.emit_expr(&s.discriminant)?;
        self.push_line(" {")?;
        for case in &s.cases {
            for item in &case.cons {
                if let Stmt::Expr(e) = item {
                    if let Expr::Member(m) = &*e.expr {
                        // Pattern: msg.tag === "Move"
                        if let Expr::Ident(tag_ident) = &m.obj {
                            if let Expr::Lit(Lit::Str(s)) = &*m.prop {
                                self.push_indent();
                                self.push(format!("{}::{}{} => ", 
                                    self.mangle(&tag_ident.sym.to_string()).to_uppercase(),
                                    self.mangle(&tag_ident.sym.to_string()),
                                    self.pascal_case(&s.value)
                                ))?;
                                // Find the body statements (everything after the comparison)
                                self.emit_switch_body(&case.cons)?;
                                break;
                            }
                        }
                    }
                }
            }
        }
        self.push_line("}")?;
        Ok(())
    }

    /// Emit switch case body.
    fn emit_switch_body(&mut self, cons: &[Stmt]) -> crate::Result<()> {
        // Skip the first statement (the comparison), emit the rest
        for (i, stmt) in cons.iter().enumerate().skip(1) {
            if i > 1 { self.push_line(";")?; }
            self.emit_stmt(stmt)?;
        }
        Ok(())
    }

    /// Emit a return statement.
    fn emit_return(&mut self, r: &ReturnStmt) -> crate::Result<()> {
        self.push("return ")?;
        if let Some(value) = &r.value {
            self.emit_expr(value)?;
        }
        Ok(())
    }

    /// Emit a type alias.
    fn emit_type_alias(&mut self, t: &TsTypeAliasDecl) -> crate::Result<()> {
        self.push(format!("pub type {} = ", self.mangle(&t.id.sym.to_string())))?;
        self.emit_ts_type(&t.type_ann)?;
        self.push(";")?;
        Ok(())
    }

    /// Emit a TypeScript enum.
    fn emit_enum(&mut self, e: &TsEnumDecl) -> crate::Result<()> {
        self.push(format!("pub enum {}", self.mangle(&e.id.sym.to_string())))?;
        self.push_line(" {")?;
        for member in &e.members {
            let tag = match &member.id {
                TsEnumMemberId::Str(s) => s.value.to_string(),
                TsEnumMemberId::Computed(_) => continue,
            };
            self.push_indent();
            self.push(format!("{},", self.pascal_case(&tag)))?;
            self.push_line("")?;
        }
        self.push("}")?;
        Ok(())
    }

    /// Emit an interface.
    fn emit_interface(&mut self, i: &TsInterfaceDecl) -> crate::Result<()> {
        self.push(format!("pub struct {} ", self.mangle(&i.id.sym.to_string())))?;
        self.emit_block_stmt(&BlockStmt {
            span: Default::default(),
            stmts: i.body.body.iter().map(|m| {
                Stmt::Decl(Decl::Var(VarDecl {
                    span: Default::default(),
                    kind: VarDeclKind::Const,
                    decls: vec![VarDeclarator {
                        span: Default::default(),
                        name: match &m {
                            TsClassMember::Property(p) => {
                                Pat::Ident(BindingIdent {
                                    id: Ident {
                                        span: Default::default(),
                                        sym: p.key.as_str().unwrap_or_default().into(),
                                        optional: false,
                                    },
                                    type_ann: None,
                                })
                            }
                            _ => Pat::Invalid(Invalid { span: Default::default() }),
                        },
                        init: None,
                        definite: false,
                    }],
                    init: None,
                }))
            }).collect(),
        })?;
        Ok(())
    }

    /// Emit a module declaration.
    fn emit_module_decl(&mut self, decl: &ModuleDecl) -> crate::Result<()> {
        match decl {
            ModuleDecl::Import(i) => self.emit_import(i),
            ModuleDecl::Export(e) => self.emit_export(e),
            _ => Ok(()),
        }
    }

    /// Emit an import.
    fn emit_import(&mut self, import: &ImportDecl) -> crate::Result<()> {
        let module_name = import.src.value.to_string();

        if module_name.starts_with("native:") {
            // Native import: native:bar -> crate::native::bar
            let path = module_name.strip_prefix("native:").unwrap_or(&module_name);
            let import = Import {
                path: format!("crate::native::{}", path.replace(".", "::")),
                names: import.specifiers.iter().filter_map(|s| {
                    match s {
                        ImportSpecifier::Named(n) => Some(ImportedName {
                            original: n.local.sym.to_string(),
                            rust_name: self.snake_case(&n.local.sym.to_string()),
                        }),
                        ImportSpecifier::Default(n) => Some(ImportedName {
                            original: "default".to_string(),
                            rust_name: n.sym.to_string(),
                        }),
                        ImportSpecifier::Namespace(n) => Some(ImportedName {
                            original: "*".to_string(),
                            rust_name: n.sym.to_string(),
                        }),
                    }
                }).collect(),
                is_native: true,
            };
            self.imports.push(import);
        } else if module_name.starts_with("./") || module_name.starts_with("../") {
            // Relative import
            let import = Import {
                path: format!("crate::generated::{}", module_name.replace("./", "").replace(".r.ts", "").replace(".r.tsx", "")),
                names: import.specifiers.iter().filter_map(|s| {
                    match s {
                        ImportSpecifier::Named(n) => Some(ImportedName {
                            original: n.local.sym.to_string(),
                            rust_name: self.snake_case(&n.local.sym.to_string()),
                        }),
                        _ => None,
                    }
                }).collect(),
                is_native: false,
            };
            self.imports.push(import);
        }

        Ok(())
    }

    /// Emit an export.
    fn emit_export(&mut self, export: &ExportDecl) -> crate::Result<()> {
        match export {
            ExportDecl::Decl(d) => self.emit_decl(d),
            ExportDecl::Named(n) => {
                for spec in &n.specifiers {
                    if let ExportSpecifier::Named(ns) = spec {
                        self.push(format!("pub use {};", self.mangle(&ns.orig.sym.to_string())))?;
                    }
                }
                Ok(())
            }
        }
    }

    /// Emit a type annotation.
    fn emit_type(&mut self, ts_type: &TsType) -> crate::Result<()> {
        self.emit_ts_type(ts_type)
    }

    /// Emit a TypeScript type.
    fn emit_ts_type(&mut self, ts_type: &TsType) -> crate::Result<()> {
        match ts_type {
            TsType::TsKeywordType(k) => {
                match k.kind {
                    TsKeywordTypeKind::TsNumberKeyword => self.push("f64"),
                    TsKeywordTypeKind::TsStringKeyword => self.push("String"),
                    TsKeywordTypeKind::TsBooleanKeyword => self.push("bool"),
                    TsKeywordTypeKind::TsNullKeyword => self.push("()"),
                    TsKeywordTypeKind::TsUndefinedKeyword => self.push("()"),
                    TsKeywordTypeKind::TsVoidKeyword => self.push("()"),
                    TsKeywordTypeKind::TsAnyType | TsKeywordTypeKind::TsUnknownType => {
                        self.push("/* unknown */ unimplemented!()")
                    }
                    _ => self.push("()"),
                }
            }
            TsType::TsArrayType(a) => {
                self.emit_ts_type(&a.elem_type)?;
                self.push("Vec<")?;
                self.emit_ts_type(&a.elem_type)?;
                self.push(">")?;
            }
            TsType::TsUnionOrIntersectionType(t) => {
                if t.ts_type_union.is_some() {
                    self.push("/* union */ unimplemented!()")?;
                } else {
                    self.push("/* intersection */ unimplemented!()")?;
                }
            }
            TsType::TsTypeRef(t) => {
                let name = t.type_name.as_str();
                match name {
                    "Array" | "Vec" => {
                        self.push("Vec<")?;
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0])?;
                            }
                        }
                        self.push(">")?;
                    }
                    "Option" => {
                        self.push("Option<")?;
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0])?;
                            }
                        }
                        self.push(">")?;
                    }
                    "Result" => {
                        self.push("Result<")?;
                        if let Some(params) = &t.type_params {
                            if params.params.len() >= 2 {
                                self.emit_ts_type(&params.params[0])?;
                                self.push(", ")?;
                                self.emit_ts_type(&params.params[1])?;
                            }
                        }
                        self.push(">")?;
                    }
                    "string" => self.push("String"),
                    "number" => self.push("f64"),
                    "boolean" => self.push("bool"),
                    "void" => self.push("()"),
                    _ => self.push(&self.mangle(name)),
                }
            }
            TsType::TsLiteralType(l) => {
                match &l.lit {
                    TsLit::Str(s) => self.push(format!("&{:?}", s.value)),
                    TsLit::Num(n) => {
                        if n.value.fract() == 0.0 {
                            self.push(format!("{}", n.value as i32));
                        } else {
                            self.push(format!("{}", n.value));
                        }
                    }
                    TsLit::BigInt(b) => self.push(format!("{}i64", b.value)),
                    TsLit::Boolean(b) => self.push(if b.value { "true" } else { "false" }),
                }
            }
            TsType::TsTupleType(t) => {
                self.push("(")?;
                for (i, elem) in t.elem_types.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    self.emit_ts_type(&elem.ty)?;
                }
                self.push(")")?;
            }
            TsType::TsParenthesizedType(p) => {
                self.emit_ts_type(&p.type_ann)?;
            }
            _ => self.push("()"),
        }
        Ok(())
    }

    /// Emit JSX.
    fn emit_jsx(&mut self, _jsx: &JsxExpr) -> crate::Result<()> {
        self.push("/* JSX */ unimplemented!()")?;
        Ok(())
    }

    // Utility methods

    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }

    fn mangle(&self, name: &str) -> String {
        if matches!(
            name,
            "as" | "async" | "await" | "break" | "const" | "continue" | "crate" | "dyn"
            | "else" | "enum" | "extern" | "false" | "fn" | "for" | "if" | "impl"
            | "in" | "let" | "loop" | "match" | "mod" | "move" | "mut" | "pub"
            | "ref" | "return" | "self" | "Self" | "static" | "struct" | "super"
            | "trait" | "true" | "type" | "unsafe" | "use" | "where" | "while"
        ) {
            format!("{}_", name)
        } else {
            self.snake_case(name)
        }
    }

    fn snake_case(&self, s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_lowercase().next().unwrap_or(c));
        }
        result
    }

    fn pascal_case(&self, s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' || c == ' ' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_uppercase().next().unwrap_or(c));
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

//! # Type Emitter
//!
//! Emits Rust type declarations from TypeScript types.

use crate::analyzer::TypeInfo;

/// Emits Rust type code.
pub struct TypeEmitter;

impl TypeEmitter {
    /// Create a new type emitter.
    pub fn new() -> Self {
        Self
    }

    /// Emit a type declaration.
    pub fn emit_type(&self, type_info: &TypeInfo) -> String {
        match type_info {
            TypeInfo::Integer(_) => "i32".to_string(),
            TypeInfo::Float => "f64".to_string(),
            TypeInfo::String => "String".to_string(),
            TypeInfo::StringLiteral(s) => format!("&str // literal: {}", s),
            TypeInfo::Boolean => "bool".to_string(),
            TypeInfo::Array(elem) => format!("Vec<{}>", self.emit_type(elem)),
            TypeInfo::Struct(s) => self.emit_struct(s),
            TypeInfo::Enum(e) => self.emit_enum(e),
            TypeInfo::Option(inner) => format!("Option<{}>", self.emit_type(inner)),
            TypeInfo::Result(ok, err) => format!("Result<{}, {}>", self.emit_type(ok), self.emit_type(err)),
            TypeInfo::Function(f) => self.emit_function(f),
            TypeInfo::Unknown => "()".to_string(),
        }
    }

    /// Emit a struct.
    fn emit_struct(&self, s: &crate::analyzer::StructInfo) -> String {
        let fields = s.fields.iter()
            .map(|(name, ty)| format!("    pub {}: {},", self.to_snake_case(name), self.emit_type(ty)))
            .collect::<Vec<_>>()
            .join("\n");

        format!(
            "struct {} {{\n{}\n}}",
            self.to_pascal_case(&s.name),
            fields
        )
    }

    /// Emit an enum.
    fn emit_enum(&self, e: &crate::analyzer::EnumInfo) -> String {
        let variants = e.variants.iter()
            .map(|v| {
                if v.fields.is_empty() {
                    format!("    {},", self.to_pascal_case(&v.tag))
                } else {
                    let fields = v.fields.iter()
                        .map(|(n, t)| format!("{}: {}", self.to_snake_case(n), self.emit_type(t)))
                        .collect::<Vec<_>>()
                        .join(", ");
                    format!("    {} {{ {} }},", self.to_pascal_case(&v.tag), fields)
                }
            })
            .collect::<Vec<_>>()
            .join("\n");

        format!(
            "enum {} {{\n{}\n}}",
            self.to_pascal_case(&e.name),
            variants
        )
    }

    /// Emit a function type.
    fn emit_function(&self, f: &crate::analyzer::FunctionInfo) -> String {
        let params = f.params.iter()
            .map(|(n, t)| format!("{}: {}", self.to_snake_case(n), self.emit_type(t)))
            .collect::<Vec<_>>()
            .join(", ");

        format!(
            "fn({}) -> {}",
            params,
            self.emit_type(&f.return_type)
        )
    }

    /// Convert to snake_case.
    fn to_snake_case(&self, s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_lowercase().next().unwrap_or(c));
        }
        result
    }

    /// Convert to PascalCase.
    fn to_pascal_case(&self, s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' || c == ' ' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_uppercase().next().unwrap_or(c));
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

impl Default for TypeEmitter {
    fn default() -> Self {
        Self::new()
    }
}

//! # JSX Transpiler
//!
//! Transpiles JSX/TSX syntax to Rust builder patterns (e.g., Ratatui).

use swc_ecma_ast::*;

/// Transpiles JSX to Rust builder patterns.
pub struct JsxTranspiler {
    /// Widget library to target
    library: WidgetLibrary,
}

/// Target widget library.
#[derive(Debug, Clone, Copy)]
pub enum WidgetLibrary {
    /// Ratatui (TUI)
    Ratatui,
    /// Iced (GUI)
    Iced,
    /// Custom
    Custom,
}

impl Default for WidgetLibrary {
    fn default() -> Self {
        Self::Ratatui
    }
}

impl JsxTranspiler {
    /// Create a new JSX transpiler.
    pub fn new(library: WidgetLibrary) -> Self {
        Self { library }
    }

    /// Transpile a JSX element.
    pub fn transpile_element(&self, elem: &JsxElement) -> String {
        let tag = match &elem.opening.name {
            JsxElementName::Ident(i) => i.sym.to_string(),
            _ => return "unimplemented!()".to_string(),
        };

        let children = elem.children.iter()
            .map(|c| self.transpile_child(c))
            .collect::<Vec<_>>()
            .join(", ");

        let attrs = elem.opening.attrs.iter()
            .map(|a| self.transpile_attr(a))
            .collect::<Vec<_>>()
            .join(", ");

        match self.library {
            WidgetLibrary::Ratatui => self.to_ratatui(&tag, &attrs, &children),
            WidgetLibrary::Iced => self.to_iced(&tag, &attrs, &children),
            WidgetLibrary::Custom => format!("{}::new({})", self.pascal_case(&tag), children),
        }
    }

    /// Transpile a JSX attribute.
    fn transpile_attr(&self, attr: &JsxAttr) -> String {
        let name = match &attr.name {
            JsxAttrName::Ident(i) => i.sym.to_string(),
            _ => return String::new(),
        };

        let value = match &attr.value {
            Some(JsxAttrValue::Str(s)) => format!("{:?}", s.value),
            Some(JsxAttrValue::ExprContainer(e)) => {
                if let Expr::JSXEmptyExpr(_) = *e.expr {
                    String::new()
                } else {
                    self.expr_to_string(&e.expr)
                }
            }
            None => String::new(),
        };

        format!(".{}({})", self.snake_case(&name), value)
    }

    /// Transpile a JSX child element.
    fn transpile_child(&self, child: &JsxChild) -> String {
        match child {
            JsxChild::Element(e) => self.transpile_element(e),
            JsxChild::Fragment(f) => {
                f.children.iter()
                    .map(|c| self.transpile_child(c))
                    .collect::<Vec<_>>()
                    .join("; ")
            }
            JsxChild::Expr(e) => {
                if let Expr::JSXEmptyExpr(_) = *e.expr {
                    String::new()
                } else {
                    self.expr_to_string(&e.expr)
                }
            }
            JsxChild::Spread(_) => String::new(),
            JsxChild::Text(t) => format!("{:?}", t.value),
        }
    }

    /// Convert expression to string.
    fn expr_to_string(&self, expr: &Expr) -> String {
        match expr {
            Expr::Lit(l) => match l {
                Lit::Str(s) => s.value.to_string(),
                Lit::Num(n) => n.value.to_string(),
                Lit::Bool(b) => b.value.to_string().to_string(),
                _ => "unimplemented!()".to_string(),
            },
            Expr::Ident(i) => i.sym.to_string(),
            Expr::Tpl(t) => {
                let mut result = String::new();
                for (i, quasi) in t.quasis.iter().enumerate() {
                    result.push_str(&quasi.raw.value);
                    if i < t.exprs.len() {
                        result.push_str("{ }");
                    }
                }
                format!("format!(\"{}\")", result)
            }
            Expr::Array(a) => {
                let elems = a.elems.iter()
                    .map(|e| e.as_ref().map(|e| self.expr_to_string(&e.expr)).unwrap_or_default())
                    .collect::<Vec<_>>()
                    .join(", ");
                format!("[{}]", elems)
            }
            Expr::Paren(p) => format!("({})", self.expr_to_string(&p.expr)),
            _ => "unimplemented!()".to_string(),
        }
    }

    /// Convert to Ratatui builder pattern.
    fn to_ratatui(&self, tag: &str, attrs: &str, _children: &str) -> String {
        match tag.to_lowercase().as_str() {
            "block" => format!("Block::default(){}", attrs),
            "list" => format!("List::new(vec![]){}", attrs),
            "listitem" => format!("ListItem::new(\"\"){}", attrs),
            "text" => format!("Paragraph::new(\"\"){}", attrs),
            "table" => format!("Table::new(vec![]){}", attrs),
            "row" => format!("Row::new(vec![]){}", attrs),
            "cell" => format!("Cell::from(\"\"){}", attrs),
            "gauge" => format!("Gauge::default(){}", attrs),
            "spinner" => format!("Sparkline::default(){}", attrs),
            "canvas" => format!("Canvas::default(){}", attrs),
            "div" | "container" => format!("Layout::default(){}", attrs),
            "span" => format!("Span::raw(\"\"){}", attrs),
            "line" => format!("Line::default(){}", attrs),
            _ => format!("/* Unknown widget: {} */ Box::new(())", tag),
        }
    }

    /// Convert to Iced builder pattern.
    fn to_iced(&self, tag: &str, attrs: &str, children: &str) -> String {
        match tag.to_lowercase().as_str() {
            "button" => format!("Button::new({})", children),
            "text" => format!("Text::new({})", children),
            "column" => format!("Column::with_children(vec![{}])", children),
            "row" => format!("Row::with_children(vec![{}])", children),
            "scrollable" => format!("Scrollable::new({})", children),
            "slider" => format!("Slider::default(){}", attrs),
            "checkbox" => format!("Checkbox::new({})", children),
            "textinput" => format!("TextInput::new({})", attrs),
            "container" => format!("Container::new({})", children),
            "scrollable" => format!("Scrollable::new({})", children),
            _ => format!("/* Unknown widget: {} */ Container::new(())", tag),
        }
    }

    /// Convert to snake_case.
    fn snake_case(&self, s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_lowercase().next().unwrap_or(c));
        }
        result
    }

    /// Convert to PascalCase.
    fn pascal_case(&self, s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' || c == ' ' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_uppercase().next().unwrap_or(c));
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

impl Default for JsxTranspiler {
    fn default() -> Self {
        Self::new(WidgetLibrary::default())
    }
}

//! # Driver Module
//!
//! Orchestrates the full compilation pipeline and integrates with Cargo.

mod build;
mod config;
mod cache;

pub use build::{BuildDriver, BuildOptions, BuildMode};
pub use config::{RuneConfig, TargetCrate};
pub use cache::CacheManager;

/// CLI commands supported by rune.
#[derive(Debug, Clone, Copy)]
pub enum Command {
    /// Development mode with hot reload
    Dev,
    /// Release build
    Build,
    /// Type check only
    Check,
    /// Transpile to stdout
    Transpile,
    /// Initialize new project
    Init,
}

impl Command {
    /// Parse from string.
    pub fn parse(s: &str) -> Option<Self> {
        match s {
            "dev" => Some(Self::Dev),
            "build" => Some(Self::Build),
            "check" => Some(Self::Check),
            "transpile" => Some(Self::Transpile),
            "init" => Some(Self::Init),
            _ => None,
        }
    }
}

/// Run the compiler with given options.
pub fn run(command: Command, options: BuildOptions) -> crate::Result<()> {
    let driver = BuildDriver::new(options)?;
    match command {
        Command::Dev => driver.dev(),
        Command::Build => driver.build(),
        Command::Check => driver.check(),
        Command::Transpile => driver.transpile(),
        Command::Init => driver.init(),
    }
}

//! # Build Driver
//!
//! Main compilation orchestration.

use std::path::{Path, PathBuf};
use std::process::Command as ProcCommand;
use crate::{Result, parser, analyzer, codegen};
use super::config::{RuneConfig, TargetCrate};
use super::cache::CacheManager;

/// Build mode.
#[derive(Debug, Clone, Copy)]
pub enum BuildMode {
    /// Development with hot reload
    Dev,
    /// Release build
    Release,
}

/// Options for building.
#[derive(Debug, Clone)]
pub struct BuildOptions {
    /// Mode to build in
    pub mode: BuildMode,
    /// Working directory
    pub workspace: PathBuf,
    /// Target crate name
    pub target_crate: Option<String>,
    /// Config file path
    pub config: Option<PathBuf>,
    /// File to transpile (for transpile command)
    pub transpile_file: Option<PathBuf>,
    /// Verbose output
    pub verbose: bool,
}

impl BuildOptions {
    /// Create new options.
    pub fn new(workspace: PathBuf) -> Self {
        Self {
            mode: BuildMode::Dev,
            workspace,
            target_crate: None,
            config: None,
            transpile_file: None,
            verbose: false,
        }
    }

    /// Set development mode.
    pub fn dev(mut self) -> Self {
        self.mode = BuildMode::Dev;
        self
    }

    /// Set release mode.
    pub fn release(mut self) -> Self {
        self.mode = BuildMode::Release;
        self
    }
}

/// Main build driver.
pub struct BuildDriver {
    options: BuildOptions,
    config: RuneConfig,
    cache: CacheManager,
}

impl BuildDriver {
    /// Create a new build driver.
    pub fn new(options: BuildOptions) -> Result<Self> {
        let config_path = options.config.clone()
            .or_else(|| options.workspace.join("rune.toml"));

        let config = if config_path.exists() {
            RuneConfig::load(&config_path)?
        } else {
            RuneConfig::default()
        };

        let cache = CacheManager::new(&options.workspace)?;

        Ok(Self {
            options,
            config,
            cache,
        })
    }

    /// Run in development mode with hot reload.
    pub fn dev(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in development mode with hot reload...");
        }

        // Scan for source files
        let sources = self.find_sources()?;
        if self.options.verbose {
            println!("Found {} Rune source files", sources.len());
        }

        // Parse and validate all sources
        let parsed = self.parse_sources(&sources)?;

        // Analyze all sources
        let analyses = self.analyze_sources(&parsed)?;

        // Generate Rust code
        let generated = self.generate_code(&parsed, &analyses)?;

        // Write to cache
        self.write_generated(&generated)?;

        // Build the crate
        self.build_crate(false)?;

        // Copy to hot directory
        self.setup_hot_reload()?;

        if self.options.verbose {
            println!("Development build complete. Dylib ready.");
        }

        Ok(())
    }

    /// Run in release mode.
    pub fn build(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in release mode...");
        }

        // Scan for source files
        let sources = self.find_sources()?;

        // Parse and analyze
        let parsed = self.parse_sources(&sources)?;
        let analyses = self.analyze_sources(&parsed)?;

        // Generate code
        let generated = self.generate_code(&parsed, &analyses)?;

        // Write to cache
        self.write_generated(&generated)?;

        // Build release
        self.build_crate(true)?;

        if self.options.verbose {
            println!("Release build complete.");
        }

        Ok(())
    }

    /// Type check only.
    pub fn check(&mut self) -> Result<()> {
        let sources = self.find_sources()?;
        let parsed = self.parse_sources(&sources)?;
        let analyses = self.analyze_sources(&parsed)?;

        for (source, analysis) in parsed.iter().zip(analyses.iter()) {
            for warning in &analysis.warnings {
                println!("warning: {} at {}", warning.message, warning.location);
            }
        }

        println!("Type check passed for {} files.", parsed.len());
        Ok(())
    }

    /// Transpile a single file to stdout.
    pub fn transpile(&mut self) -> Result<()> {
        let file = self.options.transpile_file.as_ref()
            .ok_or_else(|| crate::RuneError::Codegen("No file specified".into()))?;

        let source = parser::parse_file(file)?;
        let analysis = analyzer::analyze(&source)?;
        let module = codegen::generate(&source, &analysis)?;

        println!("{}", module.source);
        Ok(())
    }

    /// Initialize a new project.
    pub fn init(&mut self) -> Result<()> {
        let project_name = self.config.project.name.clone();
        let target_crate = self.config.build.target_crate.clone();

        // Create directory structure
        let base = self.options.workspace.join("crates").join(&target_crate);
        std::fs::create_dir_all(base.join("src/native"))?;
        std::fs::create_dir_all(base.join("src/views"))?;

        // Create Cargo.toml
        let cargo = format!(r#"# Auto-generated by rune
[package]
name = "{}"
version = "0.1.0"
edition = "2021"

[lib]
name = "{}"
path = "src/lib.rs"

[dependencies]
protocol = {{ path = "../protocol" }}
ratatui = "0.26"

[build-dependencies]
rune = {{ path = "../../.." }}
"#, target_crate, target_crate);

        std::fs::write(base.join("Cargo.toml"), cargo)?;

        // Create lib.rs
        let lib = r#"mod native;

pub struct AppState {
    pub tasks: Vec<Task>,
}

#[derive(Clone)]
pub struct Task {
    pub id: i32,
    pub title: String,
    pub done: bool,
}

#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl))
}

struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, _state: &mut AppState) {
        // TODO: Add update logic
    }

    fn render(&self, _term: &mut impl ratatui::backend::Backend, _state: &AppState) {
        // TODO: Add render logic
    }
}
"#;

        std::fs::write(base.join("src/lib.rs"), lib)?;

        // Create main.r.ts
        let main_ts = r#"// Main entry point
import { AppState, Task } from "./state.r.ts";

export function update(state: AppState): void {
    // Update logic here
}

export function render(state: AppState): void {
    // Render logic here
}
"#;

        std::fs::write(base.join("src/main.r.ts"), main_ts)?;

        // Create state.r.ts
        let state_ts = r#"// Application state types

export type Task = {
    id: number,
    title: string,
    done: boolean,
};

export type AppState = {
    tasks: Task[],
    selected: number,
};

export function createTask(title: string): Task {
    return {
        id: Date.now(),
        title,
        done: false,
    };
}

export function toggleTask(task: Task): Task {
    return { ...task, done: !task.done };
}
"#;

        std::fs::write(base.join("src/state.r.ts"), state_ts)?;

        // Create native module
        let native_mod = r#"pub mod fast_math;

pub fn batch_toggle<T>(items: &mut [T]) where T: Clone {
    for item in items.iter_mut() {
        // Toggle logic
    }
}
"#;

        std::fs::write(base.join("src/native/mod.rs"), native_mod)?;

        let fast_math = r#"/// Fast square root using native Rust
pub fn fast_sqrt(x: f64) -> f64 {
    x.sqrt()
}

/// Batch operation on numbers
pub fn batch_add(values: &[f64], n: f64) -> Vec<f64> {
    values.iter().map(|v| v + n).collect()
}
"#;

        std::fs::write(base.join("src/native/fast_math.rs"), fast_math)?;

        println!("Initialized Rune project: {}", project_name);
        println!("Created structure in crates/{}/", target_crate);

        Ok(())
    }

    /// Find all Rune source files.
    fn find_sources(&self) -> Result<Vec<PathBuf>> {
        let src_dir = self.options.workspace
            .join("crates")
            .join(&self.config.build.target_crate)
            .join("src");

        parser::scan_directory(&src_dir)
    }

    /// Parse all source files.
    fn parse_sources(&self, sources: &[PathBuf]) -> Result<Vec<parser::SourceFile>> {
        sources.iter().map(|s| parser::parse_file(s)).collect()
    }

    /// Analyze all sources.
    fn analyze_sources(&self, sources: &[parser::SourceFile]) -> Result<Vec<analyzer::AnalysisResult>] {
        sources.iter().map(|s| analyzer::analyze(s)).collect()
    }

    /// Generate Rust code from analyzed sources.
    fn generate_code(
        &self,
        sources: &[parser::SourceFile],
        analyses: &[analyzer::AnalysisResult],
    ) -> Result<Vec<codegen::GeneratedModule>> {
        sources.iter()
            .zip(analyses.iter())
            .map(|(s, a)| codegen::generate(s, a))
            .collect()
    }

    /// Write generated code to cache.
    fn write_generated(&self, modules: &[codegen::GeneratedModule]) -> Result<()> {
        let cache_dir = self.cache.generated_dir();

        for module in modules {
            let rel_path = module.name.replace(".r", "");
            let out_path = cache_dir.join(format!("{}.rs", rel_path));
            std::fs::create_dir_all(out_path.parent().unwrap())?;
            std::fs::write(&out_path, &module.source)?;
        }

        Ok(())
    }

    /// Build the target crate.
    fn build_crate(&self, release: bool) -> Result<()> {
        let manifest = self.cache.generated_cargo_toml();
        let mut cmd = ProcCommand::new("cargo");
        cmd.arg("build");
        if release {
            cmd.arg("--release");
        }
        cmd.arg("--manifest-path").arg(&manifest);

        if !self.options.verbose {
            cmd.stdout(ProcCommand::Stdio::piped());
            cmd.stderr(ProcCommand::Stdio::piped());
        }

        let output = cmd.output()
            .map_err(|e| crate::RuneError::Cargo(e.to_string()))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            return Err(crate::RuneError::Cargo(stderr.to_string()));
        }

        Ok(())
    }

    /// Set up hot reload directory.
    fn setup_hot_reload(&self) -> Result<()> {
        let hot_dir = self.options.workspace.join("target/hot");
        std::fs::create_dir_all(&hot_dir)?;

        // Find the built dylib
        let profile = if matches!(self.options.mode, BuildMode::Dev) {
            "debug"
        } else {
            "release"
        };

        let target_crate = &self.config.build.target_crate;
        let artifact_name = format!("lib{}.{}", target_crate, std::env::consts::DLIB_EXT);

        let artifact = self.options.workspace
            .join("target")
            .join(profile)
            .join(&artifact_name);

        if artifact.exists() {
            let timestamp = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_millis();

            let hot_name = format!("{}_{}.{}", artifact_name.trim_start_matches("lib"), timestamp, std::env::consts::DLIB_EXT);
            let hot_path = hot_dir.join(&hot_name);

            std::fs::copy(&artifact, &hot_path)?;

            // Update symlink
            let current = hot_dir.join(".current");
            if current.exists() {
                std::fs::remove_file(&current)?;
            }

            #[cfg(unix)]
            std::os::unix::fs::symlink(&hot_path, &current)?;

            #[cfg(windows)]
            std::os::windows::fs::symlink_file(&hot_path, &current)?;

            if self.options.verbose {
                println!("Hot reload ready: {}", hot_name);
            }
        }

        Ok(())
    }
}

