//! # App Library
//!
//! Hot-reloadable application logic.
//! This file is auto-generated - edit main.r.ts instead.

mod native;
mod generated;

// Re-export generated modules
pub use generated::*;

/// Create the app instance.
#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl::default()))
}

/// App implementation.
#[derive(Default)]
struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, state: &mut protocol::AppState) {
        generated::main::update(state);
    }

    fn render(&self, state: &protocol::AppState) -> impl ratatui::widgets::Widget {
        generated::views::root::render(state)
    }

    fn handle_key(
        &mut self,
        key: crossterm::event::KeyEvent,
        state: &mut protocol::AppState,
    ) {
        use crossterm::event::KeyCode;
        match key.code {
            KeyCode::Up | KeyCode::Char('k') => {
                if state.selected > 0 {
                    state.selected -= 1;
                }
            }
            KeyCode::Down | KeyCode::Char('j') => {
                if state.selected < state.tasks.len().saturating_sub(1) {
                    state.selected += 1;
                }
            }
            KeyCode::Enter | KeyCode::Char(' ') => {
                if let Some(task) = state.tasks.get_mut(state.selected) {
                    task.done = !task.done;
                }
            }
            KeyCode::Char('a') => {
                state.tasks.push(protocol::Task {
                    id: rand_id(),
                    title: "New Task".to_string(),
                    done: false,
                });
            }
            KeyCode::Char('d') => {
                state.tasks.remove(state.selected);
                state.selected = state.selected.saturating_sub(1);
            }
            KeyCode::Char('f') => {
                state.filter = match state.filter {
                    protocol::Filter::All => protocol::Filter::Active,
                    protocol::Filter::Active => protocol::Filter::Completed,
                    protocol::Filter::Completed => protocol::Filter::All,
                };
            }
            KeyCode::Char('q') | KeyCode::Esc => {
                state.should_exit = true;
            }
            _ => {}
        }
    }
}

/// Generate a random ID.
fn rand_id() -> i32 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_millis() as i32
}

//! Native Rust modules.
//!
//! Hand-written Rust code that coexists with .r.ts files.

pub mod fast_math;

//! Fast Math
//!
//! Hand-written Rust math functions for performance-critical operations.

/// Fast square root using native Rust.
pub fn fast_sqrt(x: f64) -> f64 {
    x.sqrt()
}

/// Batch add operation.
pub fn batch_add(values: &[f64], n: f64) -> Vec<f64> {
    values.iter().map(|v| v + n).collect()
}

/// Calculate mean of values.
pub fn mean(values: &[f64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }
    values.iter().sum::<f64>() / values.len() as f64
}

/// Calculate variance of values.
pub fn variance(values: &[f64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }
    let m = mean(values);
    values.iter().map(|v| (v - m).powi(2)).sum::<f64>() / values.len() as f64
}

/// Standard deviation.
pub fn std_dev(values: &[f64]) -> f64 {
    variance(values).sqrt()
}

// main.r.ts - Main entry point for the app logic

import { AppState, Task, Filter } from "./state.r.ts";

/**
 * Update application state.
 * Called by the host on each tick.
 */
export function update(state: AppState): void {
    // Filter tasks based on current filter
    const filtered = filterTasks(state.tasks, state.filter);

    // Clamp selected index
    if (state.selected >= filtered.length && filtered.length > 0) {
        state.selected = filtered.length - 1;
    }
}

/**
 * Filter tasks by completion status.
 */
export function filterTasks(tasks: Task[], filter: Filter): Task[] {
    switch (filter) {
        case Filter.Active:
            return tasks.filter(t => !t.done);
        case Filter.Completed:
            return tasks.filter(t => t.done);
        default:
            return tasks;
    }
}

/**
 * Get statistics about tasks.
 */
export function getStats(tasks: Task[]): { total: number; done: number; active: number } {
    const done = tasks.filter(t => t.done).length;
    return {
        total: tasks.length,
        done,
        active: tasks.length - done,
    };
}

/**
 * Find task by ID.
 */
export function findTask(tasks: Task[], id: number): Task | null {
    for (const task of tasks) {
        if (task.id === id) {
            return task;
        }
    }
    return null;
}

/**
 * Sort tasks by various criteria.
 */
export function sortTasks(tasks: Task[], by: "id" | "title" | "done"): Task[] {
    const sorted = [...tasks];
    switch (by) {
        case "id":
            return sorted.sort((a, b) => a.id - b.id);
        case "title":
            return sorted.sort((a, b) => a.title.localeCompare(b.title));
        case "done":
            return sorted.sort((a, b) => (a.done === b.done) ? 0 : a.done ? 1 : -1);
        default:
            return sorted;
    }
}

// state.r.ts - Application state types

/**
 * A task item.
 */
export type Task = {
    id: number;
    title: string;
    done: boolean;
};

/**
 * Filter mode for task list.
 */
export enum Filter {
    All = "all",
    Active = "active",
    Completed = "completed",
}

/**
 * Application state owned by host.
 */
export type AppState = {
    tasks: Task[];
    selected: number;
    filter: Filter;
    shouldExit: boolean;
};

/**
 * Message types for the app.
 */
export type Message =
    | { tag: "AddTask", title: string }
    | { tag: "ToggleTask", id: number }
    | { tag: "DeleteTask", id: number }
    | { tag: "SelectTask", index: number }
    | { tag: "SetFilter", filter: Filter }
    | { tag: "Quit" };

/**
 * Result type for operations.
 */
export type Result<T, E = string> =
    | { ok: true, value: T }
    | { ok: false, error: E };

/**
 * Create a new task.
 */
export function createTask(title: string): Task {
    return {
        id: Date.now(),
        title,
        done: false,
    };
}

/**
 * Toggle task completion.
 */
export function toggleTask(task: Task): Task {
    return { ...task, done: !task.done };
}

/**
 * Validate task title.
 */
export function validateTitle(title: string): Result<string> {
    const trimmed = title.trim();
    if (trimmed.length === 0) {
        return { ok: false, error: "Title cannot be empty" };
    }
    if (trimmed.length > 100) {
        return { ok: false, error: "Title too long (max 100 chars)" };
    }
    return { ok: true, value: trimmed };
}

// keyboard.r.ts - Keyboard event handlers

import { AppState, Task } from "../state.r.ts";

/**
 * Keyboard key codes.
 */
export enum KeyCode {
    Up = "ArrowUp",
    Down = "ArrowDown",
    Left = "ArrowLeft",
    Right = "ArrowRight",
    Enter = "Enter",
    Space = " ",
    Escape = "Escape",
    Tab = "Tab",
}

/**
 * Handle navigation keys.
 */
export function handleNavigation(key: KeyCode, state: AppState): void {
    switch (key) {
        case KeyCode.Up:
        case "k":
            if (state.selected > 0) {
                state.selected -= 1;
            }
            break;
        case KeyCode.Down:
        case "j":
            if (state.selected < state.tasks.length - 1) {
                state.selected += 1;
            }
            break;
        case KeyCode.Home:
            state.selected = 0;
            break;
        case KeyCode.End:
            state.selected = Math.max(0, state.tasks.length - 1);
            break;
    }
}

/**
 * Handle task-related keys.
 */
export function handleTaskAction(key: KeyCode, state: AppState): void {
    switch (key) {
        case KeyCode.Enter:
        case KeyCode.Space:
            toggleSelectedTask(state);
            break;
        case "d":
            deleteSelectedTask(state);
            break;
        case "a":
            addNewTask(state);
            break;
    }
}

/**
 * Toggle the currently selected task.
 */
export function toggleSelectedTask(state: AppState): void {
    const task = state.tasks[state.selected];
    if (task) {
        task.done = !task.done;
    }
}

/**
 * Delete the currently selected task.
 */
export function deleteSelectedTask(state: AppState): void {
    state.tasks.splice(state.selected, 1);
    if (state.selected >= state.tasks.length && state.tasks.length > 0) {
        state.selected = state.tasks.length - 1;
    }
}

/**
 * Add a new task.
 */
export function addNewTask(state: AppState): void {
    const task: Task = {
        id: Date.now(),
        title: "New Task",
        done: false,
    };
    state.tasks.push(task);
    state.selected = state.tasks.length - 1;
}

// api.r.ts - API handlers for task operations

import { Task, Result } from "../state.r.ts";

/**
 * Validate task data from external source.
 */
export function validateTask(task: unknown): Result<Task> {
    if (!task || typeof task !== "object") {
        return { ok: false, error: "Invalid task object" };
    }

    const t = task as Record<string, unknown>;

    if (typeof t.id !== "number") {
        return { ok: false, error: "Missing or invalid id" };
    }

    if (typeof t.title !== "string") {
        return { ok: false, error: "Missing or invalid title" };
    }

    if (typeof t.done !== "boolean") {
        return { ok: false, error: "Missing or invalid done status" };
    }

    return {
        ok: true,
        value: {
            id: t.id,
            title: t.title.trim(),
            done: t.done,
        },
    };
}

/**
 * Serialize tasks for storage.
 */
export function serializeTasks(tasks: Task[]): string {
    return JSON.stringify(tasks);
}

/**
 * Deserialize tasks from storage.
 */
export function deserializeTasks(data: string): Result<Task[]> {
    try {
        const parsed = JSON.parse(data);
        if (!Array.isArray(parsed)) {
            return { ok: false, error: "Expected array" };
        }

        const tasks: Task[] = [];
        for (const item of parsed) {
            const result = validateTask(item);
            if (!result.ok) {
                return { ok: false, error: result.error };
            }
            tasks.push(result.value);
        }

        return { ok: true, value: tasks };
    } catch (e) {
        return { ok: false, error: "Failed to parse JSON" };
    }
}

/**
 * Merge tasks from different sources.
 */
export function mergeTasks(local: Task[], remote: Task[]): Task[] {
    const merged = [...local];

    for (const remoteTask of remote) {
        const existing = merged.findIndex(t => t.id === remoteTask.id);
        if (existing >= 0) {
            // Keep newer version
            if (remoteTask !== merged[existing]) {
                merged[existing] = remoteTask;
            }
        } else {
            merged.push(remoteTask);
        }
    }

    return merged;
}

