/**
 * Checkbox component.
 */
function Checkbox(props: { checked: boolean }): string {
    return props.checked ? "[x]" : "[ ]";
}

/**
 * Footer with task statistics.
 */
function Footer(props: { tasks: Task[] }): Paragraph {
    const done = props.tasks.filter(t => t.done).length;
    const total = props.tasks.length;
    return (
        <Paragraph>
            {done}/{total} completed
        </Paragraph>
    );
}

/**
 * Progress bar using sparkline.
 */
function ProgressBar(props: { tasks: Task[] }): Widget {
    const values = props.tasks.map(t => (t.done ? 1.0 : 0.0));
    return (
        <Sparkline
            data={values}
            direction={Direction.Horizontal}
        />
    );
}

/**
 * Task list item with actions.
 */
function TaskItem(props: { task: Task; selected: boolean }): ListItem {
    return (
        <ListItem
            selected={props.selected}
            style={props.task.done ? "strikethrough" : "normal"}
        >
            {props.task.done ? "[x] " : "[ ] "}
            {props.task.title}
        </ListItem>
    );
}

// task_list.r.tsx - Task list view component

import { Task } from "../state.r.ts";
import { List, ListItem, Block } from "rune/ui";

/**
 * Props for TaskList component.
 */
interface TaskListProps {
    tasks: Task[];
    selectedIndex: number;
    showCompleted: boolean;
}

/**
 * Task list component.
 */
export function TaskList(props: TaskListProps): Widget {
    const visibleTasks = props.showCompleted
        ? props.tasks
        : props.tasks.filter(t => !t.done);

    return (
        <Block title="Tasks" borders="single">
            <List selected={props.selectedIndex}>
                {visibleTasks.map((task, i) => (
                    <TaskRow
                        key={task.id}
                        task={task}
                        isSelected={i === props.selectedIndex}
                    />
                ))}
            </List>
            {visibleTasks.length === 0 && (
                <EmptyState />
            )}
        </Block>
    );
}

/**
 * Individual task row.
 */
function TaskRow(props: { task: Task; isSelected: boolean }): ListItem {
    const checkbox = props.task.done ? "[x]" : "[ ]";
    const title = props.task.done
        ? strikethrough(props.task.title)
        : props.task.title;

    return (
        <ListItem
            selected={props.isSelected}
            highlightOnSelected={true}
        >
            {checkbox} {title}
        </ListItem>
    );
}

/**
 * Empty state message.
 */
function EmptyState(): Paragraph {
    return (
        <Paragraph align="center">
            No tasks yet. Press 'a' to add one.
        </Paragraph>
    );
}

/**
 * Apply strikethrough styling.
 */
function strikethrough(text: string): string {
    return text.split("").join("\u0336");
}

/**
 * Filter tabs component.
 */
export function FilterTabs(props: {
    current: string;
    onSelect: (filter: string) => void;
}): Widget {
    const tabs = ["All", "Active", "Completed"];

    return (
        <Block borders="simple">
            <Paragraph>
                {tabs.map(tab => (
                    <TabButton
                        key={tab}
                        label={tab}
                        active={tab === props.current}
                        onClick={() => props.onSelect(tab)}
                    />
                ))}
            </Paragraph>
        </Block>
    );
}

/**
 * Tab button component.
 */
function TabButton(props: {
    label: string;
    active: boolean;
    onClick: () => void;
}): Span {
    const prefix = props.active ? "> " : "  ";
    return <Span>{prefix}{props.label}</Span>;
}

