//! # Expression Emitter
//!
//! Emits Rust code from TypeScript expressions.

use swc_ecma_ast::*;
use crate::codegen::{CodegenOptions, GeneratedModule, Import, ImportedName};
use crate::analyzer::{AnalysisResult, BorrowMode};

/// Emits Rust code for expressions.
pub struct ExprEmitter<'a> {
    /// Output buffer
    pub output: String,
    /// Current indentation
    pub indent: usize,
    /// Analysis result
    analysis: &'a AnalysisResult,
}

impl<'a> ExprEmitter<'a> {
    /// Create a new expression emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            analysis,
        }
    }

    /// Emit an expression.
    pub fn emit_expr(&mut self, expr: &Expr) -> String {
        match expr {
            Expr::Lit(l) => self.emit_lit(l),
            Expr::Ident(i) => self.mangle(&i.sym.to_string()),
            Expr::Bin(b) => self.emit_bin_expr(b),
            Expr::Unary(u) => self.emit_unary(u),
            Expr::Update(u) => self.emit_update(u),
            Expr::Assign(a) => self.emit_assign(a),
            Expr::Member(m) => self.emit_member(m),
            Expr::Call(c) => self.emit_call(c),
            Expr::Arrow(a) => self.emit_arrow(a),
            Expr::Fn(f) => self.emit_fn_expr(f),
            Expr::Cond(c) => self.emit_cond(c),
            Expr::Array(a) => self.emit_array(a),
            Expr::Object(o) => self.emit_object(o),
            Expr::Paren(p) => {
                let inner = self.emit_expr(&p.expr);
                format!("({})", inner)
            }
            Expr::Tpl(t) => self.emit_tpl(t),
            Expr::Await(a) => {
                let inner = self.emit_expr(&a.arg);
                format!("({}.await)", inner)
            }
            Expr::TsAs(t) => self.emit_expr(&t.expr),
            _ => "unimplemented!()".to_string(),
        }
    }

    /// Emit a literal.
    fn emit_lit(&self, lit: &Lit) -> String {
        match lit {
            Lit::Null(_) => "()".to_string(),
            Lit::Bool(b) => (if b.value { "true" } else { "false" }).to_string(),
            Lit::Num(n) => {
                if n.value.fract() == 0.0 {
                    format!("{}", n.value as i32)
                } else {
                    format!("{}", n.value)
                }
            }
            Lit::Str(s) => format!("{:?}", s.value),
            Lit::BigInt(b) => format!("{}i64", b.value),
            _ => "unimplemented!()".to_string(),
        }
    }

    /// Emit a binary expression.
    fn emit_bin_expr(&self, bin: &BinExpr) -> String {
        let rust_op = match bin.op {
            BinaryOp::Add => "+",
            BinaryOp::Sub => "-",
            BinaryOp::Mul => "*",
            BinaryOp::Div => "/",
            BinaryOp::Mod => "%",
            BinaryOp::EqEq | BinaryOp::EqEqEq => "==",
            BinaryOp::NotEq | BinaryOp::NotEqEq => "!=",
            BinaryOp::Lt => "<",
            BinaryOp::Le => "<=",
            BinaryOp::Gt => ">",
            BinaryOp::Ge => ">=",
            BinaryOp::LogicalAnd => "&&",
            BinaryOp::LogicalOr => "||",
            BinaryOp::BinAnd => "&",
            BinaryOp::BinOr => "|",
            BinaryOp::BinXor => "^",
            BinaryOp::LShift => "<<",
            BinaryOp::RShift => ">>",
            BinaryOp::ZeroFillRShift => ">>",
            BinaryOp::Exp => "f64::powf",
            BinaryOp::NullishCoalescing => "unwrap_or",
        };

        let left = self.emit_expr(&bin.left);
        let right = self.emit_expr(&bin.right);

        if bin.op == BinaryOp::Exp {
            return format!("f64::powf({}, {})", left, right);
        }
        if bin.op == BinaryOp::NullishCoalescing {
            return format!("({}).unwrap_or({})", left, right);
        }

        format!("({} {} {})", left, rust_op, right)
    }

    /// Emit a unary expression.
    fn emit_unary(&self, u: &UnaryExpr) -> String {
        let rust_op = match u.op {
            UnaryOp::Minus => "-",
            UnaryOp::Plus => "",
            UnaryOp::Bang => "!",
            UnaryOp::Tilde => "!",
            UnaryOp::TypeOf => "/* typeof */ unimplemented!()",
            UnaryOp::Void => "()",
        };

        if u.op == UnaryOp::TypeOf || u.op == UnaryOp::Void {
            return rust_op.to_string();
        }

        let arg = self.emit_expr(&u.arg);
        format!("{}{}", rust_op, arg)
    }

    /// Emit an update expression.
    fn emit_update(&self, u: &UpdateExpr) -> String {
        let op = match u.op {
            UpdateOp::PlusPlus => "++",
            UpdateOp::MinusMinus => "--",
        };

        let arg = self.emit_expr(&u.arg);
        if u.is_prefix {
            format!("{}{}", op, arg)
        } else {
            format!("{}{}", arg, op)
        }
    }

    /// Emit an assignment expression.
    fn emit_assign(&self, a: &AssignExpr) -> String {
        let rust_op = match a.op {
            AssignOp::Assign => "=",
            AssignOp::AddAssign => "+=",
            AssignOp::SubAssign => "-=",
            AssignOp::MulAssign => "*=",
            AssignOp::DivAssign => "/=",
            AssignOp::ModAssign => "%=",
            _ => "=",
        };

        let left = self.emit_expr(&a.left);
        let value = self.emit_expr(&a.value);
        format!("({} {} {})", left, rust_op, value)
    }

    /// Emit a member expression.
    fn emit_member(&self, m: &MemberExpr) -> String {
        let obj = self.emit_expr(&m.obj);

        if m.computed {
            let prop = self.emit_expr(&m.prop);
            return format!("{}[{}]", obj, prop);
        }

        match &m.prop {
            Expr::Ident(i) => format!("{}.{}", obj, i.sym),
            _ => format!("{}.{}", obj, self.emit_expr(&m.prop)),
        }
    }

    /// Emit a call expression.
    fn emit_call(&self, c: &CallExpr) -> String {
        let callee = self.emit_expr(&c.callee);
        let args: Vec<String> = c.args.iter()
            .map(|a| self.emit_expr(&a.expr))
            .collect();
        format!("{}({})", callee, args.join(", "))
    }

    /// Emit an arrow function.
    fn emit_arrow(&self, a: &ArrowExpr) -> String {
        let params: Vec<String> = a.params.iter()
            .filter_map(|p| p.pat.as_ident().map(|i| self.mangle(&i.id.sym.to_string())))
            .collect();

        let body = match &a.body {
            BlockStmtOrExpr::BlockStmt(b) => {
                let stmts: Vec<String> = b.stmts.iter()
                    .map(|s| self.emit_expr_stmt(s))
                    .collect();
                format!("{{ {} }}", stmts.join("; "))
            }
            BlockStmtOrExpr::Expr(e) => self.emit_expr(e),
        };

        format!("|| {{ |{}| {} }}", params.join(", "), body)
    }

    /// Emit a function expression.
    fn emit_fn_expr(&self, f: &FnExpr) -> String {
        let params: Vec<String> = f.function.params.iter()
            .filter_map(|p| p.pat.as_ident().map(|i| self.mangle(&i.id.sym.to_string())))
            .collect();

        let body = f.function.body.as_ref()
            .map(|b| self.emit_block(b))
            .unwrap_or_default();

        format!("|{}| {}", params.join(", "), body)
    }

    /// Emit a conditional expression.
    fn emit_cond(&self, c: &CondExpr) -> String {
        let test = self.emit_expr(&c.test);
        let cons = self.emit_expr(&c.cons);
        let alt = self.emit_expr(&c.alt);
        format!("if {} {{ {} }} else {{ {} }}", test, cons, alt)
    }

    /// Emit an array literal.
    fn emit_array(&self, a: &ArrayExpr) -> String {
        let elems: Vec<String> = a.elems.iter()
            .map(|e| e.as_ref().map(|e| self.emit_expr(&e.expr)).unwrap_or_default())
            .collect();
        format!("vec![{}]", elems.join(", "))
    }

    /// Emit an object literal.
    fn emit_object(&self, o: &ObjectExpr) -> String {
        let props: Vec<String> = o.props.iter()
            .filter_map(|p| self.emit_prop(p))
            .collect();
        format!("__rune_obj!({{{}}})", props.join(", "))
    }

    /// Emit a template literal.
    fn emit_tpl(&self, t: &TplExpr) -> String {
        let mut result = String::from("format!(\"");
        let exprs: Vec<String> = t.exprs.iter()
            .map(|e| self.emit_expr(e))
            .collect();

        for (i, quasi) in t.quasis.iter().enumerate() {
            result.push_str(&quasi.raw.value.replace("{", "{{").replace("}", "}}"));
            if i < exprs.len() {
                result.push_str("{}");
            }
        }
        result.push('"');

        if !exprs.is_empty() {
            result.push_str(", ");
            result.push_str(&exprs.join(", "));
        }

        result.push(')');
        result
    }

    /// Emit a property.
    fn emit_prop(&self, prop: &PropOrSpread) -> Option<String> {
        match prop {
            PropOrSpread::Prop(Prop::KeyValue(kv)) => {
                let key = match &kv.key {
                    PropName::Str(s) => format!("{:?}: ", s.value),
                    PropName::Ident(i) => format!("{}: ", i.sym),
                    _ => return None,
                };
                let value = self.emit_expr(&kv.value);
                Some(format!("{}{}", key, value))
            }
            PropOrSpread::Spread(s) => {
                Some(format!("..{}", self.emit_expr(&s.expr)))
            }
            _ => None,
        }
    }

    /// Emit a statement as expression.
    fn emit_expr_stmt(&self, stmt: &Stmt) -> String {
        match stmt {
            Stmt::Expr(e) => self.emit_expr(&e.expr),
            Stmt::Return(r) => {
                r.value.as_ref()
                    .map(|v| format!("return {}", self.emit_expr(v)))
                    .unwrap_or_else(|| "return".to_string())
            }
            Stmt::Break(_) => "break".to_string(),
            Stmt::Continue(_) => "continue".to_string(),
            _ => "unimplemented!()".to_string(),
        }
    }

    /// Emit a block statement.
    fn emit_block(&self, block: &BlockStmt) -> String {
        let stmts: Vec<String> = block.stmts.iter()
            .map(|s| self.emit_expr_stmt(s))
            .collect();
        format!("{{ {} }}", stmts.join("; "))
    }

    /// Mangle a name to avoid keyword conflicts.
    fn mangle(&self, name: &str) -> String {
        if matches!(
            name,
            "as" | "async" | "await" | "break" | "const" | "continue" | "crate" | "dyn"
            | "else" | "enum" | "extern" | "false" | "fn" | "for" | "if" | "impl"
            | "in" | "let" | "loop" | "match" | "mod" | "move" | "mut" | "pub"
            | "ref" | "return" | "self" | "Self" | "static" | "struct" | "super"
            | "trait" | "true" | "type" | "unsafe" | "use" | "where" | "while"
        ) {
            format!("{}_", name)
        } else {
            name.to_string()
        }
    }
}

//! # Statement Emitter
//!
//! Emits Rust code from TypeScript statements.

use swc_ecma_ast::*;
use super::expr::ExprEmitter;
use crate::analyzer::AnalysisResult;

/// Emits Rust code for statements.
pub struct StmtEmitter<'a> {
    /// Output buffer
    output: String,
    /// Current indentation
    indent: usize,
    /// Expression emitter reference
    expr_emitter: ExprEmitter<'a>,
}

impl<'a> StmtEmitter<'a> {
    /// Create a new statement emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            expr_emitter: ExprEmitter::new(analysis),
        }
    }

    /// Emit a statement.
    pub fn emit_stmt(&mut self, stmt: &Stmt) {
        self.push_indent();
        match stmt {
            Stmt::Expr(e) => self.emit_expr_stmt(&e.expr),
            Stmt::If(i) => self.emit_if(i),
            Stmt::While(w) => self.emit_while(w),
            Stmt::For(f) => self.emit_for(f),
            Stmt::ForOf(f) => self.emit_for_of(f),
            Stmt::DoWhile(d) => self.emit_do_while(d),
            Stmt::Switch(s) => self.emit_switch(s),
            Stmt::Block(b) => self.emit_block(b),
            Stmt::Return(r) => self.emit_return(r),
            Stmt::Break(_) => self.push("break;"),
            Stmt::Continue(_) => self.push("continue;"),
            Stmt::Empty(_) => self.push("/* empty */;"),
            Stmt::Debugger(_) => self.push("unimplemented!();"),
            Stmt::Labeled(l) => self.emit_labeled(l),
            Stmt::Decl(d) => self.emit_decl(d),
            Stmt::Try(_) | Stmt::Throw(_) | Stmt::With(_) => {
                self.push("unreachable!() /* forbidden */;");
            }
        }
    }

    /// Get the output.
    pub fn into_output(self) -> String {
        self.output
    }

    /// Emit an expression statement.
    fn emit_expr_stmt(&mut self, expr: &Expr) {
        let code = self.expr_emitter.emit_expr(expr);
        self.push(&code);
        self.push_line(";");
    }

    /// Emit an if statement.
    fn emit_if(&mut self, i: &IfStmt) {
        let test = self.expr_emitter.emit_expr(&i.test);
        self.push("if ");
        self.push(&test);
        self.push(" ");
        self.emit_stmt_body(&i.cons);

        if let Some(alt) = &i.alt {
            self.push(" else ");
            self.emit_stmt_body(alt);
        }
    }

    /// Emit a while loop.
    fn emit_while(&mut self, w: &WhileStmt) {
        let test = self.expr_emitter.emit_expr(&w.test);
        self.push("while ");
        self.push(&test);
        self.push(" ");
        self.emit_stmt_body(&w.body);
    }

    /// Emit a for loop.
    fn emit_for(&mut self, f: &ForStmt) {
        self.push("for ");

        if let Some(init) = &f.init {
            match init {
                VarDeclOrExpr::VarDecl(v) => self.emit_var_decl(v),
                VarDeclOrExpr::Expr(e) => {
                    let code = self.expr_emitter.emit_expr(e);
                    self.push(&code);
                }
            }
        }

        if let Some(test) = &f.test {
            let code = self.expr_emitter.emit_expr(test);
            self.push(&code);
        }
        self.push("; ");

        if let Some(update) = &f.update {
            let code = self.expr_emitter.emit_expr(update);
            self.push(&code);
        }

        self.push(" ");
        self.emit_stmt_body(&f.body);
    }

    /// Emit a for-of loop.
    fn emit_for_of(&mut self, f: &ForOfStmt) {
        self.push("for ");
        self.emit_pattern(&f.left);
        self.push(" in ");

        let right = self.expr_emitter.emit_expr(&f.right);
        self.push(&right);
        self.push(" ");
        self.emit_stmt_body(&f.body);
    }

    /// Emit a do-while loop.
    fn emit_do_while(&mut self, d: &DoWhileStmt) {
        self.push("loop { ");
        self.emit_stmt(&d.body);
        self.push("if !(");
        let test = self.expr_emitter.emit_expr(&d.test);
        self.push(&test);
        self.push(") { break; } }");
        self.push_line(";");
    }

    /// Emit a switch statement.
    fn emit_switch(&mut self, s: &SwitchStmt) {
        let disc = self.expr_emitter.emit_expr(&s.discriminant);
        self.push("match ");
        self.push(&disc);
        self.push_line(" {");

        for case in &s.cases {
            for item in &case.cons {
                if let Stmt::Expr(e) = item {
                    if let Expr::Member(m) = &*e.expr {
                        if let Expr::Lit(Lit::Str(s)) = &*m.prop {
                            let var = self.expr_emitter.emit_expr(&m.obj);
                            let tag = &s.value;
                            self.push_indent();
                            self.push(&format!(
                                "{} => {{ ",
                                self.pascal_case(tag)
                            ));
                        }
                    }
                }
                self.emit_stmt(item);
                self.push_line(";");
            }
        }

        self.push_line("}");
    }

    /// Emit a block statement.
    fn emit_block(&mut self, block: &BlockStmt) {
        self.push_line("{");
        self.indent += 1;

        for stmt in &block.stmts {
            self.emit_stmt(stmt);
        }

        self.indent -= 1;
        self.push_indent();
        self.push("}");
    }

    /// Emit a return statement.
    fn emit_return(&mut self, r: &ReturnStmt) {
        self.push("return");
        if let Some(value) = &r.value {
            self.push(" ");
            let code = self.expr_emitter.emit_expr(value);
            self.push(&code);
        }
        self.push(";");
    }

    /// Emit a labeled statement.
    fn emit_labeled(&mut self, l: &LabeledStmt) {
        self.push(&format!("{}: ", l.label.sym));
        self.emit_stmt(&l.body);
    }

    /// Emit a declaration.
    fn emit_decl(&mut self, decl: &Decl) {
        match decl {
            Decl::Fn(f) => self.emit_fn_decl(f),
            Decl::Var(v) => self.emit_var_decl(v),
            Decl::TsTypeAlias(t) => self.emit_type_alias(t),
            Decl::TsEnum(e) => self.emit_enum(e),
            _ => {}
        }
    }

    /// Emit a function declaration.
    fn emit_fn_decl(&mut self, f: &FnDecl) {
        if f.function.is_async {
            self.push("pub async ");
        } else {
            self.push("pub ");
        }

        let name = self.expr_emitter.mangle(&f.ident.sym.to_string());
        self.push(&format!("fn {}(", name));

        for (i, param) in f.function.params.iter().enumerate() {
            if i > 0 { self.push(", "); }
            self.emit_fn_param(param);
        }

        self.push(")");

        if let Some(ret) = &f.function.return_type {
            self.push(" -> ");
            self.emit_ts_type(&ret.type_ann);
        }

        if let Some(body) = &f.function.body {
            self.push(" ");
            self.emit_block(body);
        } else {
            self.push(";");
        }
        self.push_line("");
    }

    /// Emit function parameters.
    fn emit_fn_param(&mut self, param: &Param) {
        let name = param.pat.as_ident()
            .map(|i| self.expr_emitter.mangle(&i.id.sym.to_string()))
            .unwrap_or_else(|| "_".to_string());

        if let Some(type_ann) = param.pat.as_ident().and_then(|i| i.type_ann.as_ref()) {
            self.push(&format!("{}: ", name));
            self.emit_ts_type(&type_ann.type_ann);
        } else {
            self.push(&name);
        }
    }

    /// Emit a variable declaration.
    fn emit_var_decl(&mut self, v: &VarDecl) {
        let keyword = match v.kind {
            VarDeclKind::Const => "let",
            VarDeclKind::Let | VarDeclKind::Var => "let mut",
        };

        for (i, decl) in v.decls.iter().enumerate() {
            if i > 0 {
                self.push_line(";");
                self.push_indent();
            }
            self.push(&format!("{} ", keyword));
            self.emit_pattern(&decl.name);

            if let Some(init) = &decl.init {
                self.push(" = ");
                let code = self.expr_emitter.emit_expr(init);
                self.push(&code);
            }
        }
    }

    /// Emit a pattern.
    fn emit_pattern(&mut self, pat: &Pat) {
        match pat {
            Pat::Ident(i) => {
                let name = self.expr_emitter.mangle(&i.id.sym.to_string());
                self.push(&name);
                if let Some(type_ann) = &i.type_ann {
                    self.push(": ");
                    self.emit_ts_type(&type_ann.type_ann);
                }
            }
            Pat::Array(a) => {
                self.push("[");
                for (i, elem) in a.elems.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    if let Some(p) = elem {
                        self.emit_pattern(p);
                    }
                }
                self.push("]");
            }
            Pat::Object(o) => {
                self.push("{");
                for (i, prop) in o.props.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    match prop {
                        ObjectPatProp::Assign(a) => {
                            self.push(&a.key.sym.to_string());
                            if let Some(v) = &a.value {
                                self.push(" = ");
                                let code = self.expr_emitter.emit_expr(&Expr::Paren(ParenExpr {
                                    span: Default::default(),
                                    expr: Box::new(v.clone()),
                                }));
                                self.push(&code);
                            }
                        }
                        ObjectPatProp::KeyValue(kv) => {
                            let key = self.expr_emitter.emit_expr(&Expr::Ident(kv.key.clone().into()));
                            self.push(&key);
                            self.push(": ");
                            self.emit_pattern(&kv.value);
                        }
                        ObjectPatProp::Rest(r) => {
                            self.push("..");
                            self.emit_pattern(&r.arg);
                        }
                    }
                }
                self.push("}");
            }
            _ => self.push("_"),
        }
    }

    /// Emit a type alias.
    fn emit_type_alias(&mut self, t: &TsTypeAliasDecl) {
        let name = self.expr_emitter.mangle(&t.id.sym.to_string());
        self.push(&format!("pub type {} = ", name));
        self.emit_ts_type(&t.type_ann);
        self.push_line(";");
    }

    /// Emit a TypeScript enum.
    fn emit_enum(&mut self, e: &TsEnumDecl) {
        let name = self.expr_emitter.mangle(&e.id.sym.to_string());
        self.push(&format!("pub enum {}", name));
        self.push_line(" {");

        for member in &e.members {
            let tag = match &member.id {
                TsEnumMemberId::Str(s) => s.value.to_string(),
                TsEnumMemberId::Computed(_) => continue,
            };
            self.push_indent();
            self.push(&format!("{},", self.pascal_case(&tag)));
            self.push_line("");
        }

        self.push_line("}");
    }

    /// Emit a TypeScript type.
    fn emit_ts_type(&mut self, ts_type: &TsType) {
        match ts_type {
            TsType::TsKeywordType(k) => {
                let ty = match k.kind {
                    TsKeywordTypeKind::TsNumberKeyword => "f64",
                    TsKeywordTypeKind::TsStringKeyword => "String",
                    TsKeywordTypeKind::TsBooleanKeyword => "bool",
                    TsKeywordTypeKind::TsNullKeyword => "()",
                    TsKeywordTypeKind::TsUndefinedKeyword => "()",
                    TsKeywordTypeKind::TsVoidKeyword => "()",
                    _ => "()",
                };
                self.push(ty);
            }
            TsType::TsArrayType(a) => {
                self.emit_ts_type(&a.elem_type);
                self.push("Vec<");
                self.emit_ts_type(&a.elem_type);
                self.push(">");
            }
            TsType::TsTypeRef(t) => {
                let name = t.type_name.as_str();
                match name {
                    "Array" | "Vec" => {
                        self.push("Vec<");
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0]);
                            }
                        }
                        self.push(">");
                    }
                    "Option" => {
                        self.push("Option<");
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0]);
                            }
                        }
                        self.push(">");
                    }
                    "Result" => {
                        self.push("Result<");
                        if let Some(params) = &t.type_params {
                            if params.params.len() >= 2 {
                                self.emit_ts_type(&params.params[0]);
                                self.push(", ");
                                self.emit_ts_type(&params.params[1]);
                            }
                        }
                        self.push(">");
                    }
                    "string" => self.push("String"),
                    "number" => self.push("f64"),
                    "boolean" => self.push("bool"),
                    "void" => self.push("()"),
                    _ => self.push(&self.expr_emitter.mangle(name)),
                }
            }
            TsType::TsTupleType(t) => {
                self.push("(");
                for (i, elem) in t.elem_types.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    self.emit_ts_type(&elem.ty);
                }
                self.push(")");
            }
            TsType::TsParenthesizedType(p) => {
                self.emit_ts_type(&p.type_ann);
            }
            _ => self.push("()"),
        }
    }

    /// Emit a statement body (handles single statement without braces).
    fn emit_stmt_body(&mut self, stmt: &Stmt) {
        match stmt {
            Stmt::Block(b) => self.emit_block(b),
            _ => {
                self.indent += 1;
                self.emit_stmt(stmt);
                self.indent -= 1;
            }
        }
    }

    /// Convert to PascalCase.
    fn pascal_case(&self, s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' || c == ' ' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_uppercase().next().unwrap_or(c));
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }

    /// Push string to output.
    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    /// Push line to output.
    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    /// Push indentation.
    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

//! # Emitters Module
//!
//! Code generation for different AST node types.

pub mod expr;
pub mod stmt;

pub use expr::ExprEmitter;
pub use stmt::StmtEmitter;

//! # Rust Emitter
//!
//! Core transpilation from TypeScript AST to Rust source.

use std::collections::HashMap;
use swc_ecma_ast::*;
use crate::{parser::SourceFile, analyzer::{AnalysisResult, BorrowMode}};
use super::{GeneratedModule, Import, ImportedName, CodegenOptions};
use super::emitters::{ExprEmitter, StmtEmitter};

/// Options for code emission.
#[derive(Debug, Clone, Default)]
pub struct EmitOptions {
    /// Generate source maps
    pub source_map: bool,
    /// Pretty print output
    pub pretty: bool,
}

/// Emits Rust code from TypeScript AST.
pub struct RustEmitter<'a> {
    source: &'a SourceFile,
    analysis: &'a AnalysisResult,
    imports: Vec<Import>,
    output: String,
    indent: usize,
    options: EmitOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            options: EmitOptions::default(),
        }
    }

    /// Emit the complete module.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        self.write_header()?;
        self.emit_module_items()?;
        self.write_footer()?;

        let name = self.source.path.file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
        })
    }

    /// Write module header.
    fn write_header(&mut self) -> crate::Result<()> {
        self.push_line("use std::collections::HashMap;");
        self.push_line("use std::fmt::{self, Write};");
        self.push_line("");
        Ok(())
    }

    /// Write module footer.
    fn write_footer(&mut self) -> crate::Result<()> {
        Ok(())
    }

    /// Emit all module items.
    fn emit_module_items(&mut self) -> crate::Result<()> {
        for item in &self.source.module.body {
            self.emit_module_item(item)?;
            self.push_line("");
        }
        Ok(())
    }

    /// Emit a single module item.
    fn emit_module_item(&mut self, item: &ModuleItem) -> crate::Result<()> {
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.emit_decl(decl),
            ModuleItem::ModuleDecl(decl) => self.emit_module_decl(decl),
            ModuleItem::Stmt(stmt) => {
                let mut emitter = StmtEmitter::new(self.analysis);
                emitter.emit_stmt(stmt);
                self.push(&emitter.into_output());
                Ok(())
            }
            _ => Ok(()),
        }
    }

    /// Emit a declaration.
    fn emit_decl(&mut self, decl: &Decl) -> crate::Result<()> {
        match decl {
            Decl::Fn(f) => self.emit_fn(f),
            Decl::Var(v) => self.emit_var_decl(v),
            Decl::TsTypeAlias(t) => self.emit_type_alias(t),
            Decl::TsEnum(e) => self.emit_enum(e),
            Decl::TsInterface(i) => self.emit_interface(i),
            _ => Ok(()),
        }
    }

    /// Emit a function.
    fn emit_fn(&mut self, f: &FnDecl) -> crate::Result<()> {
        let name = self.mangle(&f.ident.sym.to_string());

        if f.function.is_async {
            self.push("pub async ");
        } else {
            self.push("pub ");
        }

        self.push(&format!("fn {}(", name));
        self.emit_fn_params(&f.function.params)?;
        self.push(")");

        if let Some(ret) = &f.function.return_type {
            self.push(" -> ");
            self.emit_ts_type(&ret.type_ann)?;
        }

        if let Some(body) = &f.function.body {
            self.push(" ");
            self.emit_block_stmt(body)?;
        } else {
            self.push(";")?;
        }

        Ok(())
    }

    /// Emit function parameters.
    fn emit_fn_params(&mut self, params: &[Param]) -> crate::Result<()> {
        for (i, param) in params.iter().enumerate() {
            if i > 0 { self.push(", "); }
            self.emit_fn_param(param)?;
        }
        Ok(())
    }

    /// Emit function parameter.
    fn emit_fn_param(&mut self, param: &Param) -> crate::Result<()> {
        let name = param.pat.as_ident()
            .map(|i| self.mangle(&i.id.sym.to_string()))
            .unwrap_or_else(|| "_".to_string());

        let mode = self.analysis.ownership.get(&name).copied().unwrap_or(BorrowMode::Unknown);
        let prefix = match mode {
            BorrowMode::Mut => "&mut ",
            BorrowMode::Shared => "&",
            BorrowMode::Owned | BorrowMode::Unknown => "",
        };

        if let Some(type_ann) = param.pat.as_ident().and_then(|i| i.type_ann.as_ref()) {
            self.push(&format!("{prefix}{name}: "));
            self.emit_ts_type(&type_ann.type_ann)?;
        } else {
            self.push(&format!("{prefix}{name}"));
        }

        Ok(())
    }

    /// Emit a block statement.
    fn emit_block_stmt(&mut self, block: &BlockStmt) -> crate::Result<()> {
        self.push_line("{")?;
        self.indent += 1;

        for stmt in &block.stmts {
            let mut emitter = StmtEmitter::new(self.analysis);
            emitter.emit_stmt(stmt);
            self.push(&emitter.into_output());
        }

        self.indent -= 1;
        self.push("}")?;
        Ok(())
    }

    /// Emit a variable declaration.
    fn emit_var_decl(&mut self, v: &VarDecl) -> crate::Result<()> {
        let keyword = match v.kind {
            VarDeclKind::Const => "let",
            VarDeclKind::Let | VarDeclKind::Var => "let mut",
        };

        for (i, decl) in v.decls.iter().enumerate() {
            if i > 0 {
                self.push_line(";");
                self.push_indent();
            }
            self.push(&format!("{} ", keyword));
            self.emit_pat(&decl.name)?;
            if let Some(init) = &decl.init {
                self.push(" = ");
                let mut expr_emitter = ExprEmitter::new(self.analysis);
                self.push(&expr_emitter.emit_expr(init));
            }
        }
        Ok(())
    }

    /// Emit a pattern.
    fn emit_pat(&mut self, pat: &Pat) -> crate::Result<()> {
        match pat {
            Pat::Ident(i) => {
                let name = self.mangle(&i.id.sym.to_string());
                self.push(&name);
                if let Some(type_ann) = &i.type_ann {
                    self.push(": ");
                    self.emit_ts_type(&type_ann.type_ann)?;
                }
            }
            Pat::Array(a) => {
                self.push("[");
                for (i, elem) in a.elems.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    if let Some(p) = elem {
                        self.emit_pat(p)?;
                    }
                }
                self.push("]");
            }
            Pat::Object(o) => {
                self.push("{");
                for (i, prop) in o.props.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    match prop {
                        ObjectPatProp::Assign(a) => {
                            self.push(&a.key.sym.to_string());
                        }
                        ObjectPatProp::KeyValue(kv) => {
                            let mut expr_emitter = ExprEmitter::new(self.analysis);
                            self.push(&expr_emitter.emit_expr(&Expr::Ident(kv.key.clone().into()))?);
                            self.push(": ");
                            self.emit_pat(&kv.value)?;
                        }
                        ObjectPatProp::Rest(r) => {
                            self.push("..");
                            self.emit_pat(&r.arg)?;
                        }
                    }
                }
                self.push("}");
            }
            Pat::Rest(r) => {
                self.push("..");
                self.emit_pat(&r.arg)?;
            }
            _ => self.push("_"),
        }
        Ok(())
    }

    /// Emit a type alias.
    fn emit_type_alias(&mut self, t: &TsTypeAliasDecl) -> crate::Result<()> {
        self.push(&format!("pub type {} = ", self.mangle(&t.id.sym.to_string())));
        self.emit_ts_type(&t.type_ann)?;
        self.push(";")?;
        Ok(())
    }

    /// Emit a TypeScript enum.
    fn emit_enum(&mut self, e: &TsEnumDecl) -> crate::Result<()> {
        self.push(&format!("pub enum {}", self.mangle(&e.id.sym.to_string())));
        self.push_line(" {")?;

        for member in &e.members {
            let tag = match &member.id {
                TsEnumMemberId::Str(s) => s.value.to_string(),
                TsEnumMemberId::Computed(_) => continue,
            };
            self.push_indent();
            self.push(&format!("{},", self.pascal_case(&tag)));
            self.push_line("");
        }

        self.push("}")?;
        Ok(())
    }

    /// Emit an interface.
    fn emit_interface(&mut self, i: &TsInterfaceDecl) -> crate::Result<()> {
        self.push(&format!("pub struct {} ", self.mangle(&i.id.sym.to_string())))?;
        self.emit_block_stmt(&BlockStmt {
            span: Default::default(),
            stmts: Vec::new(),
        })?;
        Ok(())
    }

    /// Emit a module declaration.
    fn emit_module_decl(&mut self, decl: &ModuleDecl) -> crate::Result<()> {
        match decl {
            ModuleDecl::Import(i) => self.emit_import(i),
            ModuleDecl::Export(e) => self.emit_export(e),
            _ => Ok(()),
        }
    }

    /// Emit an import.
    fn emit_import(&mut self, import: &ImportDecl) -> crate::Result<()> {
        let module_name = import.src.value.to_string();

        if module_name.starts_with("native:") {
            let path = module_name.strip_prefix("native:").unwrap_or(&module_name);
            let import = Import {
                path: format!("crate::native::{}", path.replace(".", "::")),
                names: import.specifiers.iter().filter_map(|s| {
                    match s {
                        ImportSpecifier::Named(n) => Some(ImportedName {
                            original: n.local.sym.to_string(),
                            rust_name: self.snake_case(&n.local.sym.to_string()),
                        }),
                        ImportSpecifier::Default(n) => Some(ImportedName {
                            original: "default".to_string(),
                            rust_name: n.sym.to_string(),
                        }),
                        ImportSpecifier::Namespace(n) => Some(ImportedName {
                            original: "*".to_string(),
                            rust_name: n.sym.to_string(),
                        }),
                    }
                }).collect(),
                is_native: true,
            };
            self.imports.push(import);
        } else if module_name.starts_with("./") || module_name.starts_with("../") {
            let import = Import {
                path: format!("crate::generated::{}",
                    module_name.replace("./", "").replace(".r.ts", "").replace(".r.tsx", "")),
                names: import.specifiers.iter().filter_map(|s| {
                    match s {
                        ImportSpecifier::Named(n) => Some(ImportedName {
                            original: n.local.sym.to_string(),
                            rust_name: self.snake_case(&n.local.sym.to_string()),
                        }),
                        _ => None,
                    }
                }).collect(),
                is_native: false,
            };
            self.imports.push(import);
        }

        Ok(())
    }

    /// Emit an export.
    fn emit_export(&mut self, export: &ExportDecl) -> crate::Result<()> {
        match export {
            ExportDecl::Decl(d) => self.emit_decl(d),
            ExportDecl::Named(n) => {
                for spec in &n.specifiers {
                    if let ExportSpecifier::Named(ns) = spec {
                        self.push(&format!("pub use {};", self.mangle(&ns.orig.sym.to_string())))?;
                    }
                }
                Ok(())
            }
        }
    }

    /// Emit a TypeScript type.
    fn emit_ts_type(&mut self, ts_type: &TsType) -> crate::Result<()> {
        match ts_type {
            TsType::TsKeywordType(k) => {
                let ty = match k.kind {
                    TsKeywordTypeKind::TsNumberKeyword => "f64",
                    TsKeywordTypeKind::TsStringKeyword => "String",
                    TsKeywordTypeKind::TsBooleanKeyword => "bool",
                    TsKeywordTypeKind::TsNullKeyword => "()",
                    TsKeywordTypeKind::TsUndefinedKeyword => "()",
                    TsKeywordTypeKind::TsVoidKeyword => "()",
                    _ => "()",
                };
                self.push(ty);
            }
            TsType::TsArrayType(a) => {
                self.emit_ts_type(&a.elem_type)?;
                self.push("Vec<");
                self.emit_ts_type(&a.elem_type)?;
                self.push(">");
            }
            TsType::TsTypeRef(t) => {
                let name = t.type_name.as_str();
                match name {
                    "Array" | "Vec" => {
                        self.push("Vec<");
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0])?;
                            }
                        }
                        self.push(">");
                    }
                    "Option" => {
                        self.push("Option<");
                        if let Some(params) = &t.type_params {
                            if !params.params.is_empty() {
                                self.emit_ts_type(&params.params[0])?;
                            }
                        }
                        self.push(">");
                    }
                    "Result" => {
                        self.push("Result<");
                        if let Some(params) = &t.type_params {
                            if params.params.len() >= 2 {
                                self.emit_ts_type(&params.params[0])?;
                                self.push(", ");
                                self.emit_ts_type(&params.params[1])?;
                            }
                        }
                        self.push(">");
                    }
                    "string" => self.push("String"),
                    "number" => self.push("f64"),
                    "boolean" => self.push("bool"),
                    "void" => self.push("()"),
                    _ => self.push(&self.mangle(name)),
                }
            }
            TsType::TsTupleType(t) => {
                self.push("(");
                for (i, elem) in t.elem_types.iter().enumerate() {
                    if i > 0 { self.push(", "); }
                    self.emit_ts_type(&elem.ty)?;
                }
                self.push(")");
            }
            TsType::TsParenthesizedType(p) => {
                self.emit_ts_type(&p.type_ann)?;
            }
            _ => self.push("()"),
        }
        Ok(())
    }

    // Utility methods

    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }

    fn mangle(&self, name: &str) -> String {
        if matches!(
            name,
            "as" | "async" | "await" | "break" | "const" | "continue" | "crate" | "dyn"
            | "else" | "enum" | "extern" | "false" | "fn" | "for" | "if" | "impl"
            | "in" | "let" | "loop" | "match" | "mod" | "move" | "mut" | "pub"
            | "ref" | "return" | "self" | "Self" | "static" | "struct" | "super"
            | "trait" | "true" | "type" | "unsafe" | "use" | "where" | "while"
        ) {
            format!("{}_", name)
        } else {
            name.to_string()
        }
    }

    fn snake_case(&self, s: &str) -> String {
        let mut result = String::new();
        for (i, c) in s.chars().enumerate() {
            if c.is_uppercase() && i > 0 {
                result.push('_');
            }
            result.push(c.to_lowercase().next().unwrap_or(c));
        }
        result
    }

    fn pascal_case(&self, s: &str) -> String {
        let mut result = String::new();
        let mut capitalize_next = true;
        for c in s.chars() {
            if c == '_' || c == '-' || c == ' ' {
                capitalize_next = true;
            } else if capitalize_next {
                result.push(c.to_uppercase().next().unwrap_or(c));
                capitalize_next = false;
            } else {
                result.push(c);
            }
        }
        result
    }
}

